// GET /api/assets
// Used by Service Desk asset lookup.
// Important: this route must stay BEFORE /api/assets/:relationID.
// Source priority: TSMDM_ASSET + TS_OBJECT_ROOT, fallback HD_Assets.
function sdAssetText(value, fallback = "") {
    if (value === undefined || value === null) return fallback;
    const text = String(value).trim();
    if (!text || text === "-" || text.toLowerCase() === "null" || text.toLowerCase() === "undefined") return fallback;
    return text;
}

function sdInferAssetBrand(...values) {
    const text = values.map(value => sdAssetText(value)).filter(Boolean).join(" ").toLowerCase();
    if (!text) return "";

    const rules = [
        { brand: "Dell", keys: ["dell", "latitude", "optiplex", "precision", "vostro", "inspiron", "xps"] },
        { brand: "HP", keys: ["hewlett", "hp ", "probook", "elitebook", "zbook", "pavilion", "compaq"] },
        { brand: "Lenovo", keys: ["lenovo", "thinkpad", "thinkcentre", "ideapad", "legion"] },
        { brand: "Apple", keys: ["apple", "macbook", "imac", "mac mini", "mac pro"] },
        { brand: "Microsoft", keys: ["surface"] },
        { brand: "Acer", keys: ["acer", "aspire", "travelmate", "predator"] },
        { brand: "ASUS", keys: ["asus", "zenbook", "vivobook", "rog "] },
        { brand: "Samsung", keys: ["samsung", "galaxy"] },
        { brand: "Huawei", keys: ["huawei", "matebook"] },
        { brand: "Toshiba", keys: ["toshiba", "dynabook"] }
    ];

    const found = rules.find(rule => rule.keys.some(key => text.includes(key)));
    return found ? found.brand : "";
}

function sdNormalizeAssetRow(row) {
    const model = sdAssetText(row.model || row.Model || row.DeviceModelName || row.machineType || row.MachineType);
    const os = sdAssetText(row.os || row.OS || row.PlatformType || row.deviceType || row.DeviceType, "-");
    const name = sdAssetText(
        row.assetTag || row.name || row.computerName || row.ComputerName || row.DeviceName || row.Object_DeviceID || row.DeviceID || row.assetId || row.id,
        "-"
    );
    const brand = sdAssetText(row.brand || row.Brand || row.manufacturer || row.Manufacturer || sdInferAssetBrand(row.brand, row.Manufacturer, model, name));

    return {
        ...row,
        id: sdAssetText(row.id || row.assetId || row.AssetID || row.Object_Root_Idn || row.MDM_Asset_Idn || name),
        assetId: sdAssetText(row.assetId || row.AssetID || row.id || row.Object_Root_Idn || row.MDM_Asset_Idn || name),
        assetTag: name,
        name,
        computerName: sdAssetText(row.computerName || row.ComputerName || row.DeviceName || name, name),
        brand,
        Brand: brand,
        model,
        Model: model,
        os,
        OS: os,
        deviceType: sdAssetText(row.deviceType || row.DeviceType || os, os),
        ipAddress: sdAssetText(row.ipAddress || row.IP || row.DeviceIPAddress || row.DeviceLocalIPAddress),
        customerName: sdAssetText(row.customerName || row.CustomerName || row.Object_Full_Name || row.department),
        department: sdAssetText(row.department || row.Object_Full_Name || row.customerName || row.CustomerName)
    };
}

async function handleServiceDeskAssets(req, res) {
    try {
        const search = String(req.query.search || req.query.q || req.query.keyword || "").trim();
        const customerName = String(req.query.customerName || req.query.requester || req.query.client || "").trim();

        const pool = await sql.connect(dbConfig);
        const request = pool.request();
        request.input("SearchText", sql.NVarChar(255), `%${search}%`);
        request.input("CustomerName", sql.NVarChar(255), customerName);

        const result = await request.query(`
            SELECT TOP 500
                CAST(a.MDM_Asset_Idn AS VARCHAR(100)) AS id,
                CAST(a.MDM_Asset_Idn AS VARCHAR(100)) AS assetId,
                ISNULL(NULLIF(a.DeviceName, ''), a.DeviceID) AS assetTag,
                ISNULL(NULLIF(a.DeviceName, ''), a.DeviceID) AS name,
                ISNULL(NULLIF(a.DeviceName, ''), a.DeviceID) AS computerName,
                '' AS brand,
                ISNULL(NULLIF(a.DeviceModelName, ''), '-') AS model,
                ISNULL(NULLIF(a.PlatformType, ''), 'MDM') AS os,
                ISNULL(NULLIF(a.PlatformType, ''), 'MDM') AS deviceType,
                CASE
                    WHEN a.DeviceLocalIPAddress IS NULL OR a.DeviceLocalIPAddress = ''
                        THEN ISNULL(a.DeviceIPAddress, '')
                    ELSE a.DeviceLocalIPAddress
                END AS ipAddress,
                ISNULL(rel.Object_Full_Name, '') AS customerName,
                ISNULL(rel.Object_Full_Name, '') AS department,
                'MDM' AS source
            FROM TSMDM_ASSET a WITH (NOLOCK)
            LEFT JOIN TSMDM_OBJECT_RELATION mor WITH (NOLOCK)
                ON a.MDM_Asset_Idn = mor.MDM_Asset_Idn
            LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK)
                ON mor.Object_Rel_Idn = rel.Object_Rel_Idn
            WHERE
                (
                    @SearchText = '%%'
                    OR a.DeviceName LIKE @SearchText
                    OR a.DeviceID LIKE @SearchText
                    OR a.DeviceModelName LIKE @SearchText
                    OR a.PlatformType LIKE @SearchText
                    OR a.DeviceIPAddress LIKE @SearchText
                    OR a.DeviceLocalIPAddress LIKE @SearchText
                    OR rel.Object_Full_Name LIKE @SearchText
                )
                AND
                (
                    @CustomerName = ''
                    OR rel.Object_Full_Name = @CustomerName
                    OR rel.Object_Full_Name LIKE '%' + @CustomerName + '%'
                )

            UNION ALL

            SELECT TOP 500
                CAST(r.Object_Root_Idn AS VARCHAR(100)) AS id,
                CAST(r.Object_Root_Idn AS VARCHAR(100)) AS assetId,
                ISNULL(NULLIF(r.ComputerName, ''), r.Object_DeviceID) AS assetTag,
                ISNULL(NULLIF(r.ComputerName, ''), r.Object_DeviceID) AS name,
                ISNULL(NULLIF(r.ComputerName, ''), r.Object_DeviceID) AS computerName,
                '' AS brand,
                ISNULL(NULLIF(r.Model, ''), '-') AS model,
                'Windows' AS os,
                'Desktop' AS deviceType,
                ISNULL(r.IP, '') AS ipAddress,
                ISNULL(rel.Object_Full_Name, '') AS customerName,
                ISNULL(rel.Object_Full_Name, '') AS department,
                'EM' AS source
            FROM TS_OBJECT_ROOT r WITH (NOLOCK)
            LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK)
                ON r.Object_Rel_Idn = rel.Object_Rel_Idn
            WHERE
                (
                    @SearchText = '%%'
                    OR r.ComputerName LIKE @SearchText
                    OR r.Object_DeviceID LIKE @SearchText
                    OR r.Model LIKE @SearchText
                    OR r.IP LIKE @SearchText
                    OR rel.Object_Full_Name LIKE @SearchText
                )
                AND
                (
                    @CustomerName = ''
                    OR rel.Object_Full_Name = @CustomerName
                    OR rel.Object_Full_Name LIKE '%' + @CustomerName + '%'
                )
            ORDER BY assetTag ASC;
        `);

        let data = (result.recordset || []).map(sdNormalizeAssetRow);

        if (data.length === 0 && await tableExists(pool, "HD_Assets")) {
            const hdRequest = pool.request();
            hdRequest.input("SearchText", sql.NVarChar(255), `%${search}%`);
            hdRequest.input("CustomerName", sql.NVarChar(255), customerName);

            const hdResult = await hdRequest.query(`
                SELECT TOP 500
                    AssetID AS id,
                    AssetID AS assetId,
                    AssetTag AS assetTag,
                    AssetTag AS name,
                    AssetTag AS computerName,
                    CustomerName AS customerName,
                    DeviceType AS deviceType,
                    Brand AS brand,
                    Model AS model,
                    OS AS os,
                    IP AS ipAddress,
                    CustomerName AS department,
                    'HD' AS source
                FROM HD_Assets WITH (NOLOCK)
                WHERE
                    (
                        @SearchText = '%%'
                        OR AssetID LIKE @SearchText
                        OR AssetTag LIKE @SearchText
                        OR CustomerName LIKE @SearchText
                        OR DeviceType LIKE @SearchText
                        OR Brand LIKE @SearchText
                        OR Model LIKE @SearchText
                        OR OS LIKE @SearchText
                        OR IP LIKE @SearchText
                    )
                    AND
                    (
                        @CustomerName = ''
                        OR CustomerName = @CustomerName
                        OR CustomerName LIKE '%' + @CustomerName + '%'
                    )
                ORDER BY AssetTag ASC;
            `);

            data = (hdResult.recordset || []).map(sdNormalizeAssetRow);
        }

        return res.json(data);
    } catch (err) {
        console.error("GET /api/assets error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to retrieve assets",
            error: err.message
        });
    }
}

