app.get('/api/incident-categories', authenticateToken, async (req, res) => {
    try {
        const pool = await sql.connect(dbConfig);
        const result = await pool.request().query(`
            SELECT 
                c.CategoryID as id,
                c.Name as name,
                s.SubcategoryID as subId,
                s.Name as subName,
                d.DetailID as detailId,
                d.Name as detailName
            FROM HD_IncidentCategories c
            LEFT JOIN HD_IncidentSubcategories s ON c.CategoryID = s.CategoryID
            LEFT JOIN HD_IncidentDetails d ON s.SubcategoryID = d.SubcategoryID
            ORDER BY c.Name, s.Name, d.Name
        `);

        const categories = [];
        result.recordset.forEach(row => {
            let cat = categories.find(c => c.id === row.id);
            if (!cat) {
                cat = { id: row.id, name: row.name, subcategories: [] };
                categories.push(cat);
            }
            if (row.subId) {
                let sub = cat.subcategories.find(s => s.id === row.subId);
                if (!sub) {
                    sub = { id: row.subId, name: row.subName, details: [] };
                    cat.subcategories.push(sub);
                }
                if (row.detailId) {
                    sub.details.push({ id: row.detailId, name: row.detailName });
                }
            }
        });
        res.json(categories);
    } catch (err) {
        console.error('GET /api/incident-categories error:', err);
        res.status(500).json({ status: 'error', message: 'Failed to fetch categories', error: err.message });
    }
});

