const kbUploadsDir = path.join(__dirname, 'uploads', 'kb');
if (!fs.existsSync(kbUploadsDir)) fs.mkdirSync(kbUploadsDir, { recursive: true });

const kbStorage = multer.diskStorage({
    destination: (req, file, cb) => {
        const dir = path.join(kbUploadsDir, req.params.id);
        if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
        cb(null, dir);
    },
    filename: (req, file, cb) => {
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        const ext = path.extname(file.originalname);
        cb(null, uniqueSuffix + ext);
    }
});
const kbUpload = multer({ storage: kbStorage, limits: { fileSize: 5 * 1024 * 1024 } });

app.use('/api/uploads/kb', express.static(kbUploadsDir));

app.post('/api/knowledge-base/:id/attachments', authenticateToken, kbUpload.single('file'), (req, res) => {
    if (!req.file) return res.status(400).json({ error: 'No file uploaded' });
    const attachment = {
        filename: req.file.filename,
        originalName: req.file.originalname,
        size: req.file.size,
        url: `/api/uploads/kb/${req.params.id}/${req.file.filename}`,
        uploadedAt: new Date().toISOString()
    };
    const metaPath = path.join(kbUploadsDir, req.params.id, '_meta.json');
    let meta = [];
    if (fs.existsSync(metaPath)) meta = JSON.parse(fs.readFileSync(metaPath, 'utf8'));
    meta.push(attachment);
    fs.writeFileSync(metaPath, JSON.stringify(meta, null, 2));
    res.json(attachment);
});

app.get('/api/knowledge-base/:id/attachments', authenticateToken, (req, res) => {
    const metaPath = path.join(kbUploadsDir, req.params.id, '_meta.json');
    if (!fs.existsSync(metaPath)) return res.json([]);
    const meta = JSON.parse(fs.readFileSync(metaPath, 'utf8'));
    res.json(meta);
});

app.delete('/api/knowledge-base/:id/attachments/:filename', authenticateToken, (req, res) => {
    const filePath = path.join(kbUploadsDir, req.params.id, req.params.filename);
    const metaPath = path.join(kbUploadsDir, req.params.id, '_meta.json');
    if (fs.existsSync(filePath)) fs.unlinkSync(filePath);
    if (fs.existsSync(metaPath)) {
        let meta = JSON.parse(fs.readFileSync(metaPath, 'utf8'));
        meta = meta.filter(a => a.filename !== req.params.filename);
        fs.writeFileSync(metaPath, JSON.stringify(meta, null, 2));
    }
    res.json({ message: 'Deleted' });
});

// ============================================================
// ADVANCED SEARCH API - Find Incident
// ============================================================

app.post('/api/incidents/search', authenticateToken, async (req, res) => {
    try {
        const {
            keyword,
            dateRange,
            incidentType,
            statuses,
            asset,
            assignment,
            slaStatus
        } = req.body;

        const pool = await sql.connect(dbConfig);
        let query = `
            SELECT 
                IncidentID as id,
                Title as title,
                Description as description,
                Priority as priority,
                Status as status,
                Category as category,
                CreatedAt as createdAt,
                CustomerID as customerId,
                CustomerName as customerName,
                Sector as sector,
                DeviceType as deviceType,
                AssetID as assetId,
                Subcategory as subcategory,
                IncidentDetail as incidentDetail,
                ReporterID as reporterId,
                SlaDue as slaDue,
                AssignedTo as assignedTo,
                AssignedLevel as assignedLevel,
                FirstResponseAt as firstResponseAt,
                ResolvedAt as resolvedAt,
                RootCause as rootCause,
                ActionPlan as actionPlan,
                AdditionalMemo as additionalMemo,
                Remarks as remarks,
                UserType as userType
            FROM HD_Incidents
            WHERE 1=1
        `;
        
        const conditions = [];
        const request = pool.request();
        let paramCounter = 1;

        // 1. Keyword Search
        if (keyword) {
            if (keyword.reqNo) {
                conditions.push(`IncidentID LIKE @reqNo${paramCounter}`);
                request.input(`reqNo${paramCounter}`, sql.NVarChar, `%${keyword.reqNo}%`);
                paramCounter++;
            }
            if (keyword.requester) {
                conditions.push(`CustomerName LIKE @requester${paramCounter}`);
                request.input(`requester${paramCounter}`, sql.NVarChar, `%${keyword.requester}%`);
                paramCounter++;
            }
            if (keyword.incidentTitle) {
                conditions.push(`Title LIKE @title${paramCounter}`);
                request.input(`title${paramCounter}`, sql.NVarChar, `%${keyword.incidentTitle}%`);
                paramCounter++;
            }
            if (keyword.assetTag) {
                conditions.push(`AssetID LIKE @assetTag${paramCounter}`);
                request.input(`assetTag${paramCounter}`, sql.NVarChar, `%${keyword.assetTag}%`);
                paramCounter++;
            }
            if (keyword.ipAddress) {
                // IP address would need to join with Assets table
                conditions.push(`EXISTS (SELECT 1 FROM HD_Assets WHERE HD_Assets.AssetID = HD_Incidents.AssetID AND HD_Assets.IP LIKE @ip${paramCounter})`);
                request.input(`ip${paramCounter}`, sql.NVarChar, `%${keyword.ipAddress}%`);
                paramCounter++;
            }
        }

        // 2. Date Range
        if (dateRange && dateRange.type === 'custom') {
            if (dateRange.startDate) {
                conditions.push(`CAST(CreatedAt AS DATE) >= @startDate`);
                request.input('startDate', sql.Date, dateRange.startDate);
            }
            if (dateRange.endDate) {
                conditions.push(`CAST(CreatedAt AS DATE) <= @endDate`);
                request.input('endDate', sql.Date, dateRange.endDate);
            }
        }

        // 3. Incident Type (Cascading)
        if (incidentType) {
            if (incidentType.category) {
                conditions.push(`Category = @category`);
                request.input('category', sql.NVarChar, incidentType.category);
            }
            if (incidentType.subcategory) {
                conditions.push(`Subcategory = @subcategory`);
                request.input('subcategory', sql.NVarChar, incidentType.subcategory);
            }
            if (incidentType.detail) {
                conditions.push(`IncidentDetail = @detail`);
                request.input('detail', sql.NVarChar, incidentType.detail);
            }
        }

        // 4. Status Filter (Multiple selection)
        if (statuses && statuses.length > 0) {
            const placeholders = statuses.map((_, i) => `@status${i}`).join(',');
            conditions.push(`Status IN (${placeholders})`);
            statuses.forEach((status, i) => {
                request.input(`status${i}`, sql.NVarChar, status);
            });
        }

        // 5. Asset Information
        if (asset) {
            if (asset.deviceType) {
                conditions.push(`DeviceType = @deviceType`);
                request.input('deviceType', sql.NVarChar, asset.deviceType);
            }
            // Brand and Model would need to join with Assets table
            if (asset.brand || asset.model) {
                let assetJoinCondition = '';
                if (asset.brand) {
                    assetJoinCondition += ` AND a.Brand = @brand`;
                    request.input('brand', sql.NVarChar, asset.brand);
                }
                if (asset.model) {
                    assetJoinCondition += ` AND a.Model = @model`;
                    request.input('model', sql.NVarChar, asset.model);
                }
                conditions.push(`EXISTS (SELECT 1 FROM HD_Assets a WHERE a.AssetID = HD_Incidents.AssetID ${assetJoinCondition})`);
            }
        }

        // 6. Assignment
        if (assignment) {
            if (assignment.supportLevel && assignment.supportLevel !== 'All') {
                conditions.push(`AssignedLevel = @supportLevel`);
                request.input('supportLevel', sql.NVarChar, assignment.supportLevel);
            }
            if (assignment.engineer) {
                conditions.push(`AssignedTo = @engineer`);
                request.input('engineer', sql.NVarChar, assignment.engineer);
            }
        }

        // 7. SLA Status
        if (slaStatus && slaStatus !== 'All') {
            const now = new Date().toISOString();
            if (slaStatus === 'On Time') {
                conditions.push(`SlaDue IS NOT NULL AND SlaDue > GETDATE() AND Status != 'Resolved'`);
            } else if (slaStatus === 'Near Due') {
                conditions.push(`SlaDue IS NOT NULL AND SlaDue <= DATEADD(hour, 24, GETDATE()) AND SlaDue > GETDATE() AND Status != 'Resolved'`);
            } else if (slaStatus === 'Overdue') {
                conditions.push(`SlaDue IS NOT NULL AND SlaDue < GETDATE() AND Status != 'Resolved'`);
            }
        }

        // Apply all conditions
        if (conditions.length > 0) {
            query += ` AND ${conditions.join(' AND ')}`;
        }

        // Add ordering
        query += ` ORDER BY CreatedAt DESC`;

        console.log('Search Query:', query);
        const result = await request.query(query);
        
        res.json({
            success: true,
            data: result.recordset,
            total: result.recordset.length,
            filters: req.body
        });
        
    } catch (err) {
        console.error('POST /api/incidents/search error:', err);
        res.status(500).json({ 
            success: false, 
            message: 'Failed to search incidents', 
            error: err.message 
        });
    }
});

