app.get('/api/engineer-availability/unavailable-by-date', authenticateToken, async (req, res) => {
    try {
        const { year, month } = req.query;
        const targetYear = parseInt(year, 10) || new Date().getFullYear();
        const targetMonth = parseInt(month, 10) || new Date().getMonth() + 1;
        const pool = await sql.connect(dbConfig);
        await ensureEmaEngineerAvailabilityTable(pool);

        const result = await pool.request()
            .input('YearValue', sql.Int, targetYear)
            .input('MonthValue', sql.Int, targetMonth)
            .query(`
                SELECT
                    ea.StartDate,
                    ea.EndDate,
                    ea.UserID,
                    u.FullName AS EngineerName,
                    roleList.RoleNames AS EngineerRole,
                    u.Department,
                    ea.Status,
                    ea.Remarks
                FROM EMA_EngineerAvailability ea WITH (NOLOCK)
                INNER JOIN EMA_Users u WITH (NOLOCK)
                    ON u.UserID = ea.UserID
                OUTER APPLY (
                    SELECT STUFF((
                        SELECT ', ' + r.RoleName
                        FROM EMA_UserRoles ur WITH (NOLOCK)
                        INNER JOIN EMA_Roles r WITH (NOLOCK)
                            ON r.RoleID = ur.RoleID
                        WHERE ur.UserID = u.UserID
                          AND ISNULL(r.Status, 'Active') <> 'Inactive'
                        ORDER BY ur.IsPrimary DESC, r.RoleName ASC
                        FOR XML PATH(''), TYPE
                    ).value('.', 'NVARCHAR(MAX)'), 1, 2, '') AS RoleNames
                ) roleList
                WHERE ea.IsActive = 1
                  AND ea.EndDate >= CAST(GETDATE() AS DATE)
                  AND (
                    (YEAR(ea.StartDate) = @YearValue AND MONTH(ea.StartDate) = @MonthValue)
                    OR (YEAR(ea.EndDate) = @YearValue AND MONTH(ea.EndDate) = @MonthValue)
                    OR (ea.StartDate <= DATEFROMPARTS(@YearValue, @MonthValue, 1)
                        AND ea.EndDate >= EOMONTH(DATEFROMPARTS(@YearValue, @MonthValue, 1)))
                  )
                ORDER BY ea.StartDate ASC, u.FullName ASC;
            `);

        const unavailableByDate = {};
        const today = new Date().toISOString().slice(0, 10);

        for (const record of result.recordset || []) {
            const startDate = new Date(record.StartDate);
            const endDate = new Date(record.EndDate);
            const currentDate = new Date(startDate);

            while (currentDate <= endDate) {
                const dateStr = currentDate.toISOString().slice(0, 10);
                const currentYear = currentDate.getFullYear();
                const currentMonth = currentDate.getMonth() + 1;

                if (currentYear === targetYear && currentMonth === targetMonth && dateStr >= today) {
                    if (!unavailableByDate[dateStr]) unavailableByDate[dateStr] = [];
                    unavailableByDate[dateStr].push({
                        engineerName: record.EngineerName,
                        role: record.EngineerRole,
                        department: record.Department,
                        status: record.Status,
                        remarks: record.Remarks,
                        startDate: record.StartDate,
                        endDate: record.EndDate
                    });
                }

                currentDate.setDate(currentDate.getDate() + 1);
            }
        }

        return res.json(unavailableByDate);
    } catch (err) {
        console.error('GET /api/engineer-availability/unavailable-by-date error:', err);
        return res.status(500).json({ success: false, message: err.message });
    }
});

app.delete('/api/engineer-availability/:id', authenticateToken, async (req, res) => {
    try {
        const id = parseInt(req.params.id, 10);
        const pool = await sql.connect(dbConfig);
        await ensureEmaEngineerAvailabilityTable(pool);

        const result = await pool.request()
            .input('Id', sql.Int, id)
            .input('UpdatedBy', sql.NVarChar, req.user?.userID || req.user?.username || 'system')
            .query(`
                UPDATE EMA_EngineerAvailability
                SET IsActive = 0,
                    UpdatedAt = GETDATE(),
                    UpdatedBy = @UpdatedBy
                OUTPUT DELETED.*
                WHERE Id = @Id
                  AND IsActive = 1;
            `);

        if (!result.recordset || result.recordset.length === 0) {
            return res.status(404).json({ success: false, message: 'Schedule not found.' });
        }

        await logEmaAudit(pool, req, 'Removed engineer leave schedule', 'Resource Planning', 'Warning', {
            before: result.recordset[0]
        }, { entityType: 'EngineerAvailability', entityID: String(id) });

        return res.json({ success: true, message: 'Engineer leave schedule removed.' });
    } catch (err) {
        console.error('DELETE /api/engineer-availability/:id error:', err);
        return res.status(500).json({ success: false, message: err.message });
    }
});



// ============================================================
// EMAUNI SETTINGS API
// Added for Settings.tsx sections:
// General, User Directory, Role & Permission, Client Directory,
// Incident Config, Notification Channels, Security & Auth, Audit Logs
// ============================================================

function safeJsonParse(value, fallbackValue) {
    try {
        if (!value) return fallbackValue;
        return JSON.parse(value);
    } catch (err) {
        return fallbackValue;
    }
}

async function getSettingValue(pool, key, fallbackValue = null) {
    const result = await pool.request()
        .input("SettingKey", sql.NVarChar, key)
        .query(`
            SELECT TOP 1 SettingValue
            FROM EMA_Settings
            WHERE SettingKey = @SettingKey
        `);

    if (result.recordset.length === 0) return fallbackValue;
    return result.recordset[0].SettingValue;
}

async function upsertSettingValue(pool, key, value, updatedBy) {
    await pool.request()
        .input("SettingKey", sql.NVarChar, key)
        .input("SettingValue", sql.NVarChar(sql.MAX), value == null ? "" : String(value))
        .input("UpdatedBy", sql.NVarChar, updatedBy || "system")
        .query(`
            MERGE EMA_Settings AS target
            USING (SELECT @SettingKey AS SettingKey) AS source
            ON target.SettingKey = source.SettingKey
            WHEN MATCHED THEN
                UPDATE SET SettingValue = @SettingValue, UpdatedBy = @UpdatedBy, UpdatedAt = GETDATE()
            WHEN NOT MATCHED THEN
                INSERT (SettingKey, SettingValue, UpdatedBy)
                VALUES (@SettingKey, @SettingValue, @UpdatedBy);
        `);
}

async function ensureEmaAuditLogsTable(pool) {
    await pool.request().query(`
        IF OBJECT_ID('dbo.EMA_AuditLogs', 'U') IS NULL
        BEGIN
            CREATE TABLE dbo.EMA_AuditLogs (
                LogID INT IDENTITY(1,1) NOT NULL PRIMARY KEY,
                UserName NVARCHAR(200) NULL,
                Module NVARCHAR(200) NULL,
                Action NVARCHAR(300) NOT NULL,
                Severity NVARCHAR(50) NOT NULL CONSTRAINT DF_EMA_AuditLogs_Severity DEFAULT 'Info',
                Details NVARCHAR(MAX) NULL,
                EntityType NVARCHAR(150) NULL,
                EntityID NVARCHAR(150) NULL,
                IpAddress NVARCHAR(100) NULL,
                UserAgent NVARCHAR(600) NULL,
                CreatedAt DATETIME NOT NULL CONSTRAINT DF_EMA_AuditLogs_CreatedAt DEFAULT GETDATE()
            );
        END;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'UserName') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD UserName NVARCHAR(200) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'Module') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD Module NVARCHAR(200) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'Action') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD Action NVARCHAR(300) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'Severity') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD Severity NVARCHAR(50) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'Details') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD Details NVARCHAR(MAX) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'EntityType') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD EntityType NVARCHAR(150) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'EntityID') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD EntityID NVARCHAR(150) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'IpAddress') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD IpAddress NVARCHAR(100) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'UserAgent') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD UserAgent NVARCHAR(600) NULL;

        IF COL_LENGTH('dbo.EMA_AuditLogs', 'CreatedAt') IS NULL
            ALTER TABLE dbo.EMA_AuditLogs ADD CreatedAt DATETIME NULL;

        UPDATE dbo.EMA_AuditLogs
        SET Severity = 'Info'
        WHERE Severity IS NULL OR LTRIM(RTRIM(Severity)) = '';

        UPDATE dbo.EMA_AuditLogs
        SET CreatedAt = GETDATE()
        WHERE CreatedAt IS NULL;

        UPDATE dbo.EMA_AuditLogs
        SET Action = 'Audit event'
        WHERE Action IS NULL OR LTRIM(RTRIM(Action)) = '';
    `);

    await pool.request().query(`
        IF NOT EXISTS (
            SELECT 1
            FROM sys.indexes
            WHERE name = 'IX_EMA_AuditLogs_CreatedAt'
              AND object_id = OBJECT_ID('dbo.EMA_AuditLogs')
        )
        BEGIN
            CREATE INDEX IX_EMA_AuditLogs_CreatedAt ON dbo.EMA_AuditLogs(CreatedAt DESC);
        END;

        IF NOT EXISTS (
            SELECT 1
            FROM sys.indexes
            WHERE name = 'IX_EMA_AuditLogs_Module_Severity'
              AND object_id = OBJECT_ID('dbo.EMA_AuditLogs')
        )
        BEGIN
            CREATE INDEX IX_EMA_AuditLogs_Module_Severity ON dbo.EMA_AuditLogs(Module, Severity, CreatedAt DESC);
        END;
    `);
}

function normalizeAuditSeverity(value) {
    const text = String(value || 'Info').trim().toLowerCase();
    if (['success', 'succeeded', 'ok'].includes(text)) return 'Success';
    if (['warning', 'warn'].includes(text)) return 'Warning';
    if (['error', 'failed', 'failure', 'danger'].includes(text)) return 'Error';
    return 'Info';
}

function stringifyAuditDetails(details) {
    if (details === undefined || details === null) return '';
    if (typeof details === 'string') return details;

    try {
        return JSON.stringify(details);
    } catch (err) {
        return String(details);
    }
}

function getAuditRequestUser(req) {
    return normalizeAuthValue(
        req?.user?.userID ||
        req?.user?.username ||
        req?.user?.email ||
        req?.body?.updatedBy ||
        req?.body?.createdBy ||
        'system',
        'system'
    );
}

async function logEmaAudit(pool, req, action, moduleName, severity = 'Info', details = '', meta = {}) {
    try {
        await ensureEmaAuditLogsTable(pool);

        const userName = getAuditRequestUser(req);
        const detailText = stringifyAuditDetails(sanitizeAuditDetails(details));
        const ipAddress = normalizeAuthValue(req?.headers?.['x-forwarded-for'] || req?.ip || req?.socket?.remoteAddress || '', '');
        const userAgent = normalizeAuthValue(req?.headers?.['user-agent'] || '', '');

        await pool.request()
            .input('UserName', sql.NVarChar(200), userName)
            .input('Module', sql.NVarChar(200), normalizeAuthValue(moduleName, 'Settings'))
            .input('Action', sql.NVarChar(300), normalizeAuthValue(action, 'Audit event'))
            .input('Severity', sql.NVarChar(50), normalizeAuditSeverity(severity))
            .input('Details', sql.NVarChar(sql.MAX), detailText)
            .input('EntityType', sql.NVarChar(150), normalizeAuthValue(meta.entityType || meta.EntityType || '', ''))
            .input('EntityID', sql.NVarChar(150), normalizeAuthValue(meta.entityID || meta.EntityID || meta.entityId || '', ''))
            .input('IpAddress', sql.NVarChar(100), ipAddress)
            .input('UserAgent', sql.NVarChar(600), userAgent)
            .query(`
                INSERT INTO dbo.EMA_AuditLogs
                (
                    UserName,
                    Module,
                    Action,
                    Severity,
                    Details,
                    EntityType,
                    EntityID,
                    IpAddress,
                    UserAgent,
                    CreatedAt
                )
                VALUES
                (
                    @UserName,
                    @Module,
                    @Action,
                    @Severity,
                    @Details,
                    NULLIF(@EntityType, ''),
                    NULLIF(@EntityID, ''),
                    NULLIF(@IpAddress, ''),
                    NULLIF(@UserAgent, ''),
                    GETDATE()
                );
            `);
    } catch (auditErr) {
        console.error('Audit log failed:', auditErr.message);
    }
}


function sanitizeAuditDetails(value, depth = 0) {
    if (depth > 5) return '[MaxDepth]';
    if (value === undefined || value === null) return value;
    if (value instanceof Date) return value.toISOString();

    if (Array.isArray(value)) {
        return value.slice(0, 100).map((item) => sanitizeAuditDetails(item, depth + 1));
    }

    if (typeof value === 'object') {
        const output = {};
        const blockedKey = /(password|passcode|token|secret|hash|qr|otpauth|cookie|authorization|refresh)/i;

        for (const [key, itemValue] of Object.entries(value)) {
            if (blockedKey.test(key)) {
                output[key] = '[REDACTED]';
                continue;
            }
            output[key] = sanitizeAuditDetails(itemValue, depth + 1);
        }

        return output;
    }

    return value;
}

function normalizeAuditCompareValue(value) {
    if (value === undefined) return null;
    if (value instanceof Date) return value.toISOString();
    if (typeof value === 'string') return value.trim();
    return value;
}

function buildAuditChangedFields(before = {}, after = {}, allowedFields = null) {
    const beforeObj = before || {};
    const afterObj = after || {};
    const fieldSet = allowedFields && Array.isArray(allowedFields)
        ? new Set(allowedFields)
        : new Set([...Object.keys(beforeObj), ...Object.keys(afterObj)]);

    const blockedKey = /(password|passcode|token|secret|hash|qr|otpauth|cookie|authorization|refresh)/i;
    const changes = [];

    for (const field of fieldSet) {
        if (blockedKey.test(field)) continue;

        const beforeValue = normalizeAuditCompareValue(beforeObj[field]);
        const afterValue = normalizeAuditCompareValue(afterObj[field]);

        if (JSON.stringify(beforeValue) !== JSON.stringify(afterValue)) {
            changes.push({
                field,
                before: beforeValue,
                after: afterValue
            });
        }
    }

    return changes;
}

function getAuditEntityId(row = {}, ...keys) {
    for (const key of keys) {
        if (row && row[key] !== undefined && row[key] !== null && String(row[key]).trim() !== '') {
            return String(row[key]);
        }
    }
    return '';
}

function buildPricingAuditAction(actionType, beforeRow, afterRow) {
    const beforeExcluded = beforeRow ? Boolean(beforeRow.IsExcluded ?? beforeRow.isExcluded) : null;
    const afterExcluded = afterRow ? Boolean(afterRow.IsExcluded ?? afterRow.isExcluded) : null;

    if (actionType === 'create') {
        return afterExcluded ? 'Created device pricing rule excluded from CAPEX' : 'Created device pricing rule';
    }

    if (actionType === 'delete') {
        return beforeExcluded ? 'Deleted CAPEX-excluded device pricing rule' : 'Deleted device pricing rule';
    }

    if (beforeExcluded !== null && beforeExcluded !== afterExcluded) {
        return afterExcluded ? 'Excluded device pricing from CAPEX' : 'Included device pricing in CAPEX';
    }

    return 'Updated device pricing rule';
}


