// USER DIRECTORY - EMA_Users v2 user access source
// HD_Users is intentionally not used here. It can be used later for one-time migration only.
function normalizeEmaUserStatus(value) {
    const text = String(value || "Active").trim();
    const allowed = new Set(["Active", "Review", "Locked", "Inactive"]);
    return allowed.has(text) ? text : "Active";
}

function parseEmaBit(value, fallback = false) {
    if (value === undefined || value === null || value === "") return fallback;
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value !== 0;
    const text = String(value).trim().toLowerCase();
    if (["true", "1", "yes", "y", "on"].includes(text)) return true;
    if (["false", "0", "no", "n", "off"].includes(text)) return false;
    return fallback;
}

function normalizeEmaDate(value) {
    if (!value) return null;
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function buildEmaUsername(username, email, fullName) {
    const explicitUsername = String(username || "").trim();
    if (explicitUsername) return explicitUsername;

    const emailText = String(email || "").trim();
    if (emailText && emailText.includes("@")) return emailText.split("@")[0];

    const nameText = String(fullName || "").trim().toLowerCase();
    const generated = nameText.replace(/[^a-z0-9]+/g, ".").replace(/^\.+|\.+$/g, "");
    return generated || `user.${Date.now()}`;
}


function splitEmaRoleNames(value) {
    if (Array.isArray(value)) {
        return value.map((item) => String(item || "").trim()).filter(Boolean);
    }
    return String(value || "")
        .split(/[,|;]/)
        .map((item) => item.trim())
        .filter(Boolean);
}

function uniqueEmaRoleNames(value) {
    const seen = new Set();
    const output = [];
    for (const role of splitEmaRoleNames(value)) {
        const key = role.toLowerCase();
        if (!key || seen.has(key)) continue;
        seen.add(key);
        output.push(role);
    }
    return output;
}

function getRequestedEmaRoles(body) {
    return uniqueEmaRoleNames(body.roles || body.roleNames || body.roleName || body.role || []);
}

function makeEmaRoleKey(name) {
    const key = String(name || "")
        .trim()
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "_")
        .replace(/^_+|_+$/g, "");
    return key || `role_${Date.now()}`;
}

async function assertEmaRolesTable(pool) {
    const exists = await tableExists(pool, "EMA_Roles");
    if (!exists) {
        const error = new Error("EMA_Roles table does not exist. Run the RBAC database script first.");
        error.statusCode = 500;
        throw error;
    }
}

async function assertEmaUserRolesTable(pool) {
    const exists = await tableExists(pool, "EMA_UserRoles");
    if (!exists) {
        const error = new Error("EMA_UserRoles table does not exist. Run the RBAC database script first.");
        error.statusCode = 500;
        throw error;
    }
}

async function getEmaUserRoleNameMap(pool, userIds) {
    const ids = [...new Set((userIds || []).map((id) => Number(id)).filter(Boolean))];
    if (ids.length === 0) return new Map();

    await assertEmaRolesTable(pool);
    await assertEmaUserRolesTable(pool);

    const request = pool.request();
    const params = ids.map((id, index) => {
        const key = `UserID${index}`;
        request.input(key, sql.Int, id);
        return `@${key}`;
    }).join(",");

    const result = await request.query(`
        SELECT
            ur.UserID,
            r.RoleName
        FROM EMA_UserRoles ur WITH (NOLOCK)
        INNER JOIN EMA_Roles r WITH (NOLOCK)
            ON r.RoleID = ur.RoleID
        WHERE ur.UserID IN (${params})
          AND ISNULL(r.Status, 'Active') <> 'Inactive'
        ORDER BY ur.IsPrimary DESC, ur.AssignedAt ASC, r.RoleName ASC;
    `);

    const map = new Map();
    for (const row of result.recordset || []) {
        const list = map.get(row.UserID) || [];
        list.push(row.RoleName);
        map.set(row.UserID, list);
    }

    return map;
}

async function applyEmaUserRoles(pool, userID, roleNames, assignedBy = "system") {
    await assertEmaRolesTable(pool);
    await assertEmaUserRolesTable(pool);

    const roles = uniqueEmaRoleNames(roleNames);
    await pool.request()
        .input("UserID", sql.Int, userID)
        .query("DELETE FROM EMA_UserRoles WHERE UserID = @UserID");

    if (roles.length === 0) return [];

    const assigned = [];
    for (let index = 0; index < roles.length; index += 1) {
        const roleName = roles[index];
        const roleResult = await pool.request()
            .input("RoleName", sql.NVarChar, roleName)
            .query(`
                SELECT TOP 1 RoleID, RoleName
                FROM EMA_Roles WITH (NOLOCK)
                WHERE RoleName = @RoleName
                  AND ISNULL(Status, 'Active') <> 'Inactive';
            `);

        if (roleResult.recordset.length === 0) {
            const error = new Error(`Role '${roleName}' does not exist or is inactive.`);
            error.statusCode = 400;
            throw error;
        }

        const role = roleResult.recordset[0];
        await pool.request()
            .input("UserID", sql.Int, userID)
            .input("RoleID", sql.Int, role.RoleID)
            .input("IsPrimary", sql.Bit, index === 0 ? 1 : 0)
            .input("AssignedBy", sql.NVarChar, assignedBy)
            .query(`
                INSERT INTO EMA_UserRoles (UserID, RoleID, IsPrimary, AssignedAt, AssignedBy)
                VALUES (@UserID, @RoleID, @IsPrimary, GETDATE(), @AssignedBy);
            `);
        assigned.push(role.RoleName);
    }

    return assigned;
}

function mapEmaUserResponse(row) {
    const requireMFA = row.RequireMFA === true || row.RequireMFA === 1;
    const accountLocked = row.AccountLocked === true || row.AccountLocked === 1 || row.Status === "Locked";

    return {
        id: row.UserID,
        userID: row.UserID,
        legacyUserID: row.LegacyUserID || null,
        username: row.Username || "",
        name: row.FullName || row.Username || "",
        fullName: row.FullName || row.Username || "",
        email: row.Email || "",
        role: row.RoleNames || row.RoleName || "",
        roleName: row.RoleNames || row.RoleName || "",
        roles: uniqueEmaRoleNames(row.RoleNames || row.RoleName || []),
        scope: row.AccessScope || "EMA + Dashboard",
        accessScope: row.AccessScope || "EMA + Dashboard",
        department: row.Department || "",
        position: row.Position || "",
        phoneNo: row.PhoneNo || "",
        status: row.Status || "Active",
        isActive: row.IsActive === true || row.IsActive === 1,
        requireMFA,
        mfa: requireMFA,
        twoFactorEnabled: row.TwoFactorEnabled === true || row.TwoFactorEnabled === 1,
        hasTwoFactorSecret: Boolean(normalizeAuthValue(row.TwoFactorSecret)),
        twoFactorVerifiedAt: row.TwoFactorVerifiedAt || null,
        twoFactorResetAt: row.TwoFactorResetAt || null,
        accountLocked,
        lockReason: row.LockReason || "",
        accessStartDate: row.AccessStartDate || null,
        accessEndDate: row.AccessEndDate || null,
        lastLoginAt: row.LastLoginAt || null,
        passwordChangedAt: row.PasswordChangedAt || null,
        loginFailCount: Number(row.LoginFailCount || 0),
        remarks: row.Remarks || "",
        createdAt: row.CreatedAt || null,
        updatedAt: row.UpdatedAt || row.CreatedAt || null
    };
}

async function ensureEmaUsersPasswordColumns(pool) {
    const hasEmaUsers = await tableExists(pool, "EMA_Users");
    if (!hasEmaUsers) return false;

    await pool.request().query(`
        IF COL_LENGTH('dbo.EMA_Users', 'PasswordHash') IS NULL
            ALTER TABLE dbo.EMA_Users ADD PasswordHash NVARCHAR(255) NULL;

        IF COL_LENGTH('dbo.EMA_Users', 'PasswordChangedAt') IS NULL
            ALTER TABLE dbo.EMA_Users ADD PasswordChangedAt DATETIME NULL;
    `);

    return true;
}

async function assertEmaUsersTable(pool) {
    const exists = await tableExists(pool, "EMA_Users");
    if (!exists) {
        const error = new Error("EMA_Users table does not exist. Run the EMA_Users database script first.");
        error.statusCode = 500;
        throw error;
    }

    await ensureEmaUsersPasswordColumns(pool);
    await ensureEmaUsers2faColumns(pool);
}

const emaUserSelectColumns = `
    UserID,
    LegacyUserID,
    Username,
    FullName,
    Email,
    RoleName,
    AccessScope,
    Department,
    Position,
    PhoneNo,
    Status,
    IsActive,
    RequireMFA,
    TwoFactorEnabled,
    TwoFactorSecret,
    TwoFactorVerifiedAt,
    TwoFactorResetAt,
    AccountLocked,
    LockReason,
    AccessStartDate,
    AccessEndDate,
    LastLoginAt,
    PasswordChangedAt,
    LoginFailCount,
    Remarks,
    CreatedAt,
    UpdatedAt
`;

async function getEmaUserById(pool, userID) {
    const result = await pool.request()
        .input("UserID", sql.Int, userID)
        .query(`
            SELECT TOP 1
                ${emaUserSelectColumns}
            FROM EMA_Users WITH (NOLOCK)
            WHERE UserID = @UserID
        `);

    return result.recordset?.[0] || null;
}

app.get("/api/settings/users", authenticateToken, async (req, res) => {
    try {
        const pool = await sql.connect(dbConfig);
        await assertEmaUsersTable(pool);

        const result = await pool.request().query(`
            SELECT
                ${emaUserSelectColumns}
            FROM EMA_Users WITH (NOLOCK)
            ORDER BY
                CASE WHEN Status = 'Active' THEN 0 WHEN Status = 'Review' THEN 1 WHEN Status = 'Locked' THEN 2 ELSE 3 END,
                ISNULL(UpdatedAt, CreatedAt) DESC,
                FullName ASC,
                Username ASC
        `);

        const rows = result.recordset || [];
        const roleMap = await getEmaUserRoleNameMap(pool, rows.map((row) => row.UserID));
        const data = rows.map((row) => mapEmaUserResponse({
            ...row,
            RoleNames: (roleMap.get(row.UserID) || splitEmaRoleNames(row.RoleName)).join(", ")
        }));

        return res.json({ success: true, data });
    } catch (err) {
        console.error("GET /api/settings/users error:", err);
        return res.status(err.statusCode || 500).json({ success: false, message: err.message });
    }
});

app.get("/api/settings/users/:id", authenticateToken, async (req, res) => {
    try {
        const userID = parseInt(req.params.id, 10);
        if (!userID) {
            return res.status(400).json({ success: false, message: "Invalid user ID." });
        }

        const pool = await sql.connect(dbConfig);
        await assertEmaUsersTable(pool);

        const row = await getEmaUserById(pool, userID);
        if (!row) {
            return res.status(404).json({ success: false, message: "User not found." });
        }

        const roleMap = await getEmaUserRoleNameMap(pool, [userID]);
        return res.json({
            success: true,
            data: mapEmaUserResponse({ ...row, RoleNames: (roleMap.get(userID) || splitEmaRoleNames(row.RoleName)).join(", ") })
        });
    } catch (err) {
        console.error("GET /api/settings/users/:id error:", err);
        return res.status(err.statusCode || 500).json({ success: false, message: err.message });
    }
});

app.post("/api/settings/users", authenticateToken, async (req, res) => {
    try {
        const fullName = String(req.body.fullName || req.body.name || "").trim();
        const email = String(req.body.email || "").trim();
        const username = buildEmaUsername(req.body.username, email, fullName);
        const accountLocked = parseEmaBit(req.body.accountLocked, false);
        const status = accountLocked ? "Locked" : normalizeEmaUserStatus(req.body.status);
        const roleNames = getRequestedEmaRoles(req.body);
        const passwordText = String(req.body.password || req.body.newPassword || "").trim();

        if (!fullName && !username) {
            return res.status(400).json({ success: false, message: "Full name or username is required." });
        }

        if (!passwordText || passwordText.length < 8) {
            return res.status(400).json({ success: false, message: "Password must be at least 8 characters." });
        }

        const passwordHash = await bcrypt.hash(passwordText, 10);

        const pool = await sql.connect(dbConfig);
        await assertEmaUsersTable(pool);

        const duplicate = await pool.request()
            .input("Username", sql.NVarChar, username)
            .input("Email", sql.NVarChar, email)
            .query(`
                SELECT TOP 1 UserID
                FROM EMA_Users WITH (NOLOCK)
                WHERE Username = @Username
                   OR (@Email <> '' AND Email = @Email)
            `);

        if (duplicate.recordset.length > 0) {
            return res.status(409).json({ success: false, message: "Username or email already exists." });
        }

        const result = await pool.request()
            .input("LegacyUserID", sql.Int, req.body.legacyUserID || null)
            .input("Username", sql.NVarChar, username)
            .input("FullName", sql.NVarChar, fullName || username)
            .input("Email", sql.NVarChar, email)
            .input("RoleName", sql.NVarChar, roleNames.join(", "))
            .input("AccessScope", sql.NVarChar, req.body.accessScope || req.body.scope || "EMA + Dashboard")
            .input("Department", sql.NVarChar, req.body.department || "")
            .input("Position", sql.NVarChar, req.body.position || "")
            .input("PhoneNo", sql.NVarChar, req.body.phoneNo || "")
            .input("Status", sql.NVarChar, status)
            .input("IsActive", sql.Bit, status === "Inactive" ? 0 : 1)
            .input("RequireMFA", sql.Bit, parseEmaBit(req.body.requireMFA ?? req.body.mfa, false) ? 1 : 0)
            .input("AccountLocked", sql.Bit, accountLocked ? 1 : 0)
            .input("LockReason", sql.NVarChar, accountLocked ? (req.body.lockReason || "Locked by administrator") : "")
            .input("AccessStartDate", sql.DateTime, normalizeEmaDate(req.body.accessStartDate))
            .input("AccessEndDate", sql.DateTime, normalizeEmaDate(req.body.accessEndDate))
            .input("LoginFailCount", sql.Int, parseInt(req.body.loginFailCount, 10) || 0)
            .input("Remarks", sql.NVarChar, req.body.remarks || "")
            .input("PasswordHash", sql.NVarChar(255), passwordHash)
            .input("CreatedBy", sql.NVarChar, req.user?.userID || "system")
            .query(`
                INSERT INTO EMA_Users
                (
                    LegacyUserID,
                    Username,
                    FullName,
                    Email,
                    RoleName,
                    AccessScope,
                    Department,
                    Position,
                    PhoneNo,
                    Status,
                    IsActive,
                    RequireMFA,
                    AccountLocked,
                    LockReason,
                    AccessStartDate,
                    AccessEndDate,
                    LoginFailCount,
                    Remarks,
                    PasswordHash,
                    PasswordChangedAt,
                    CreatedAt,
                    CreatedBy
                )
                OUTPUT
                    ${emaUserSelectColumns.replace(/\bUserID\b/g, "INSERTED.UserID").replace(/\bLegacyUserID\b/g, "INSERTED.LegacyUserID").replace(/\bUsername\b/g, "INSERTED.Username").replace(/\bFullName\b/g, "INSERTED.FullName").replace(/\bEmail\b/g, "INSERTED.Email").replace(/\bRoleName\b/g, "INSERTED.RoleName").replace(/\bAccessScope\b/g, "INSERTED.AccessScope").replace(/\bDepartment\b/g, "INSERTED.Department").replace(/\bPosition\b/g, "INSERTED.Position").replace(/\bPhoneNo\b/g, "INSERTED.PhoneNo").replace(/\bStatus\b/g, "INSERTED.Status").replace(/\bIsActive\b/g, "INSERTED.IsActive").replace(/\bRequireMFA\b/g, "INSERTED.RequireMFA").replace(/\bTwoFactorEnabled\b/g, "INSERTED.TwoFactorEnabled").replace(/\bTwoFactorSecret\b/g, "INSERTED.TwoFactorSecret").replace(/\bTwoFactorVerifiedAt\b/g, "INSERTED.TwoFactorVerifiedAt").replace(/\bTwoFactorResetAt\b/g, "INSERTED.TwoFactorResetAt").replace(/\bAccountLocked\b/g, "INSERTED.AccountLocked").replace(/\bLockReason\b/g, "INSERTED.LockReason").replace(/\bAccessStartDate\b/g, "INSERTED.AccessStartDate").replace(/\bAccessEndDate\b/g, "INSERTED.AccessEndDate").replace(/\bLastLoginAt\b/g, "INSERTED.LastLoginAt").replace(/\bPasswordChangedAt\b/g, "INSERTED.PasswordChangedAt").replace(/\bLoginFailCount\b/g, "INSERTED.LoginFailCount").replace(/\bRemarks\b/g, "INSERTED.Remarks").replace(/\bCreatedAt\b/g, "INSERTED.CreatedAt").replace(/\bUpdatedAt\b/g, "INSERTED.UpdatedAt")}
                VALUES
                (
                    @LegacyUserID,
                    @Username,
                    @FullName,
                    @Email,
                    @RoleName,
                    @AccessScope,
                    @Department,
                    @Position,
                    @PhoneNo,
                    @Status,
                    @IsActive,
                    @RequireMFA,
                    @AccountLocked,
                    @LockReason,
                    @AccessStartDate,
                    @AccessEndDate,
                    @LoginFailCount,
                    @Remarks,
                    @PasswordHash,
                    GETDATE(),
                    GETDATE(),
                    @CreatedBy
                )
            `);

        const createdRow = result.recordset[0];
        const assignedRoles = await applyEmaUserRoles(pool, createdRow.UserID, roleNames, req.user?.userID || "system");
        const data = mapEmaUserResponse({ ...createdRow, RoleNames: assignedRoles.join(", ") });
        await logEmaAudit(pool, req, "Created EMA user", "User Access Management", "Success", data);
        return res.json({ success: true, data });
    } catch (err) {
        console.error("POST /api/settings/users error:", err);
        return res.status(err.statusCode || 500).json({ success: false, message: err.message });
    }
});

