// Keep API failures JSON-formatted instead of Express HTML error pages.

/*
|--------------------------------------------------------------------------
| MDM / SureMDM Text Message APIs - MERGED FROM server_sendmessage.js
|--------------------------------------------------------------------------
| Used by HardwareInventory.tsx Send Message action.
| Sends SureMDM Text_Message dynamic job to one EM/MDM device or platform.
|--------------------------------------------------------------------------
*/

function pickSureMdmDevice(devices, match = {}) {
    const targetDeviceID = normalizeMdmValue(match.deviceID).toLowerCase();
    const targetName = normalizeMdmValue(match.deviceName).toLowerCase();

    if (!Array.isArray(devices) || devices.length === 0) return null;

    if (targetDeviceID) {
        const byId = devices.find(device => {
            return normalizeMdmValue(firstMdmDefined(device.DeviceID, device.deviceID, device.DeviceId, device.id)).toLowerCase() === targetDeviceID;
        });
        if (byId) return byId;
    }

    if (targetName) {
        const exact = devices.find(device => {
            return normalizeMdmValue(firstMdmDefined(device.DeviceName, device.deviceName, device.RealDeviceName, device.Hostname, device.name)).toLowerCase() === targetName;
        });
        if (exact) return exact;

        const loose = devices.find(device => {
            return normalizeMdmValue(firstMdmDefined(device.DeviceName, device.deviceName, device.RealDeviceName, device.Hostname, device.name)).toLowerCase().includes(targetName);
        });
        if (loose) return loose;
    }

    return devices[0];
}

async function searchSureMdmDeviceByName(deviceName, limit = 20) {
    const searchValue = normalizeMdmValue(deviceName);
    if (!searchValue) throw new Error("DeviceName is required for SureMDM device search.");

    const payload = {
        ID: "AllDevices",
        IsSearch: true,
        Limit: limit,
        SearchColumns: ["DeviceName"],
        SearchValue: searchValue,
        SortColumn: "LastTimeStamp",
        SortOrder: "asc"
    };

    const response = await callSureMdmApi("device", {
        method: "POST",
        contentType: "application/json",
        data: payload
    });

    const devices = asSureMdmArray(response.data);
    const device = pickSureMdmDevice(devices, { deviceName: searchValue });

    if (!device) {
        const err = new Error(`SureMDM device '${searchValue}' was not found.`);
        err.responseData = response.data;
        throw err;
    }

    return {
        device,
        devices,
        raw: response.data,
        requestUrl: response.url
    };
}

async function getEmTextMessageCandidate(pool, objectRootIdn) {
    const result = await pool.request()
        .input("Object_Root_Idn", sql.Int, objectRootIdn)
        .query(`
            SELECT TOP 1
                r.Object_Root_Idn,
                r.Object_DeviceID AS EM_Object_DeviceID,
                r.ComputerName,
                r.Object_Client_Name,
                r.Model,
                map.MDM_Asset_Idn,
                a.DeviceID AS MDM_DeviceID,
                a.DeviceName AS MDM_DeviceName,
                a.PlatformType AS MDM_PlatformType,
                a.AgentVersion AS MDM_AgentVersion,
                a.ConnectionStatus AS MDM_ConnectionStatus
            FROM TS_OBJECT_ROOT r
            LEFT JOIN TSMDM_TS_OBJECT_MAPPING map
                ON map.Object_Root_Idn = r.Object_Root_Idn
            LEFT JOIN TSMDM_ASSET a
                ON a.MDM_Asset_Idn = map.MDM_Asset_Idn
            WHERE r.Object_Root_Idn = @Object_Root_Idn;
        `);

    return result.recordset?.[0] || null;
}

async function getMdmAssetsForTextMessage(pool, mdmAssetIdn = 0, platformType = "") {
    const result = await pool.request()
        .input("MDM_Asset_Idn", sql.Int, mdmAssetIdn)
        .input("PlatformType", sql.VarChar(255), normalizeMdmValue(platformType))
        .query(`
            SELECT *,
                   CASE WHEN DeviceLocalIPAddress IS NULL OR DeviceLocalIPAddress = ''
                        THEN DeviceIPAddress ELSE DeviceLocalIPAddress END AS IPAddress
            FROM TSMDM_ASSET
            WHERE (@MDM_Asset_Idn = 0 OR MDM_Asset_Idn = @MDM_Asset_Idn)
              AND (@PlatformType = '' OR PlatformType LIKE @PlatformType + '%')
            ORDER BY DeviceName ASC;
        `);

    return result.recordset || [];
}

function buildSureMdmTextMessagePayload(subject, body, forceRead = false, options = {}) {
    return {
        Subject: normalizeMdmValue(subject),
        Body: normalizeMdmValue(body),
        ReadNotification: parseMdmBoolean(options.ReadNotification ?? options.readNotification, true),
        ForceRead: parseMdmBoolean(forceRead, false),
        EnableBuzz: parseMdmBoolean(options.EnableBuzz ?? options.enableBuzz, false),
        BuzzInterval: normalizeMdmValue(options.BuzzInterval ?? options.buzzInterval),
        CloseDurationEnable: parseMdmBoolean(options.CloseDurationEnable ?? options.closeDurationEnable, false),
        Interval: normalizeMdmValue(options.Interval ?? options.interval),
        RichTextBody: normalizeMdmValue(options.RichTextBody ?? options.richTextBody),
        RichTextHtml: normalizeMdmValue(options.RichTextHtml ?? options.richTextHtml)
    };
}

function encodeSureMdmPayloadToBase64(payload) {
    const json = typeof payload === "string" ? payload : JSON.stringify(payload);
    return Buffer.from(json, "utf8").toString("base64");
}

function normalizeSureMdmDynamicJobResponse(data) {
    const rawMessage = normalizeMdmValue(firstMdmDefined(
        data?.message,
        data?.Message,
        data?.status,
        data?.Status
    ));

    const lower = rawMessage.toLowerCase();
    let message = "Failed";

    if (lower === "success" || lower.includes("successfully") || lower.includes("success")) {
        message = "Success";
    } else if (lower.includes("error") || lower.includes("exception")) {
        message = "Error";
    }

    return {
        message,
        rawMessage,
        raw: data
    };
}

async function assignSureMdmDynamicTextMessage(deviceID, subject, body, forceRead = false, options = {}) {
    const sureMdmDeviceID = normalizeMdmValue(deviceID);
    if (!sureMdmDeviceID) throw new Error("SureMDM DeviceID is required to send a text message.");

    const messagePayload = buildSureMdmTextMessagePayload(subject, body, forceRead, options);
    const encodedPayload = encodeSureMdmPayloadToBase64(messagePayload);

    const requestPayload = {
        DeviceID: sureMdmDeviceID,
        JobType: "Text_Message",
        PayLoad: encodedPayload
    };

    const response = await callSureMdmApi("v2/dynamicjob", {
        method: "POST",
        contentType: "application/json",
        data: requestPayload,
        timeout: options.timeout
    });

    return {
        ...normalizeSureMdmDynamicJobResponse(response.data),
        requestPayload: {
            DeviceID: requestPayload.DeviceID,
            JobType: requestPayload.JobType,
            PayLoad: requestPayload.PayLoad
        },
        decodedPayload: messagePayload,
        requestUrl: response.url
    };
}

async function resolveSureMdmDeviceIDFromName(deviceName) {
    const searchResult = await searchSureMdmDeviceByName(deviceName, 20);
    const selectedDevice = searchResult.device || {};
    const sureMdmDeviceID = normalizeMdmValue(firstMdmDefined(
        selectedDevice.DeviceID,
        selectedDevice.deviceID,
        selectedDevice.DeviceId,
        selectedDevice.id
    ));

    if (!sureMdmDeviceID) {
        throw new Error(`SureMDM device '${deviceName}' was found, but the response did not contain DeviceID.`);
    }

    return {
        deviceID: sureMdmDeviceID,
        deviceName: normalizeMdmValue(firstMdmDefined(
            selectedDevice.DeviceName,
            selectedDevice.deviceName,
            selectedDevice.RealDeviceName,
            selectedDevice.Hostname,
            deviceName
        )),
        selectedDevice,
        raw: searchResult.raw
    };
}

async function resolveTextMessageTargetByObjectRoot(pool, objectRootIdn) {
    if (!objectRootIdn) throw new Error("Object_Root_Idn is required.");

    let localAsset = await getMdmAssetByObjectRoot(pool, objectRootIdn, { syncMapping: true });

    if (!localAsset) {
        localAsset = await getEmTextMessageCandidate(pool, objectRootIdn);
    }

    if (!localAsset) {
        throw new Error(`EM asset was not found for Object_Root_Idn '${objectRootIdn}'.`);
    }

    let deviceID = normalizeMdmValue(firstMdmDefined(
        localAsset.DeviceID,
        localAsset.MDM_DeviceID
    ));

    let deviceName = normalizeMdmValue(firstMdmDefined(
        localAsset.DeviceName,
        localAsset.MDM_DeviceName,
        localAsset.ComputerName,
        localAsset.Object_Client_Name
    ));

    let sureMdmLookup = null;
    if (!deviceID && deviceName) {
        sureMdmLookup = await resolveSureMdmDeviceIDFromName(deviceName);
        deviceID = sureMdmLookup.deviceID;
        deviceName = sureMdmLookup.deviceName || deviceName;
    }

    if (!deviceID) {
        throw new Error(`Could not resolve SureMDM DeviceID for Object_Root_Idn '${objectRootIdn}'.`);
    }

    return {
        objectAgent: "EM",
        Object_Root_Idn: objectRootIdn,
        MDM_Asset_Idn: localAsset.MDM_Asset_Idn || 0,
        deviceID,
        deviceName,
        platformType: normalizeMdmValue(firstMdmDefined(localAsset.PlatformType, localAsset.MDM_PlatformType, "Windows")),
        localAsset,
        sureMdmLookup
    };
}

async function resolveTextMessageTargetByMdmAsset(pool, mdmAssetIdn, requested = {}) {
    const requestedDeviceID = normalizeMdmValue(firstMdmDefined(
        requested.MDM_DeviceID,
        requested.mdmDeviceID,
        requested.DeviceID,
        requested.deviceID,
        requested.deviceId,
        requested.Object_DeviceID,
        requested.objectDeviceID
    ));

    const requestedDeviceName = normalizeMdmValue(firstMdmDefined(
        requested.DeviceName,
        requested.deviceName,
        requested.ComputerName,
        requested.computerName
    ));

    let localAsset = null;
    if (mdmAssetIdn) localAsset = await getMdmAssetByMdmAssetId(pool, mdmAssetIdn);
    if (!localAsset && requestedDeviceID) localAsset = await getMdmAssetByDeviceID(pool, requestedDeviceID);

    let deviceID = normalizeMdmValue(firstMdmDefined(localAsset?.DeviceID, requestedDeviceID));
    let deviceName = normalizeMdmValue(firstMdmDefined(localAsset?.DeviceName, requestedDeviceName));

    let sureMdmLookup = null;
    if (!deviceID && deviceName) {
        sureMdmLookup = await resolveSureMdmDeviceIDFromName(deviceName);
        deviceID = sureMdmLookup.deviceID;
        deviceName = sureMdmLookup.deviceName || deviceName;
    }

    if (!deviceID) {
        throw new Error("MDM_Asset_Idn, DeviceID, or DeviceName is required to send a SureMDM text message.");
    }

    return {
        objectAgent: "MDM",
        MDM_Asset_Idn: mdmAssetIdn || localAsset?.MDM_Asset_Idn || 0,
        deviceID,
        deviceName,
        platformType: normalizeMdmValue(localAsset?.PlatformType),
        localAsset,
        sureMdmLookup
    };
}

function extractTextMessageBody(req) {
    const body = req.body || {};
    const subject = normalizeMdmValue(firstMdmDefined(body.Subject, body.subject));
    const messageBody = normalizeMdmValue(firstMdmDefined(body.Body, body.body, body.Message, body.messageText));
    const forceRead = parseMdmBoolean(firstMdmDefined(body.ForceRead, body.forceRead), false);

    const options = {
        ReadNotification: body.ReadNotification ?? body.readNotification,
        EnableBuzz: body.EnableBuzz ?? body.enableBuzz,
        BuzzInterval: body.BuzzInterval ?? body.buzzInterval,
        CloseDurationEnable: body.CloseDurationEnable ?? body.closeDurationEnable,
        Interval: body.Interval ?? body.interval,
        RichTextBody: body.RichTextBody ?? body.richTextBody,
        RichTextHtml: body.RichTextHtml ?? body.richTextHtml
    };

    if (!subject) throw new Error("Subject is required.");
    if (!messageBody) throw new Error("Body is required.");

    return { subject, messageBody, forceRead, options };
}

async function handleSendMdmTextMessageByObject(req, res) {
    try {
        const { subject, messageBody, forceRead, options } = extractTextMessageBody(req);
        const objectRootIdn = parseMdmInt(firstMdmDefined(
            req.body?.Object_Root_Idn,
            req.body?.objectRootIdn,
            req.body?.objectRootID,
            req.body?.assetId
        ), 0);

        if (!objectRootIdn) {
            return res.status(400).json({ success: false, message: "Object_Root_Idn is required." });
        }

        const pool = await getSqlPoolWithRetry();
        const target = await resolveTextMessageTargetByObjectRoot(pool, objectRootIdn);
        const result = await assignSureMdmDynamicTextMessage(target.deviceID, subject, messageBody, forceRead, options);

        return res.json({
            success: result.message === "Success",
            message: result.message,
            data: [{
                ...result,
                Object_Root_Idn: target.Object_Root_Idn,
                MDM_Asset_Idn: target.MDM_Asset_Idn,
                DeviceID: target.deviceID,
                DeviceName: target.deviceName,
                PlatformType: target.platformType
            }]
        });
    } catch (err) {
        const responseData = err.response?.data || err.responseData;
        return res.status(500).json({
            success: false,
            message: "Unable to send message to this device.",
            errorMessage: getMdmErrorMessage(responseData, err.message || String(err)),
            data: [{ message: "Error", errorMessage: err.message || String(err) }]
        });
    }
}

async function handleSendMdmTextMessageByMdmAsset(req, res) {
    try {
        const { subject, messageBody, forceRead, options } = extractTextMessageBody(req);
        const mdmAssetIdn = parseMdmInt(firstMdmDefined(
            req.body?.MDM_Asset_Idn,
            req.body?.mdmAssetIdn,
            req.body?.mdmAssetID,
            req.body?.assetId
        ), 0);

        const pool = await getSqlPoolWithRetry();
        const target = await resolveTextMessageTargetByMdmAsset(pool, mdmAssetIdn, req.body || {});
        const result = await assignSureMdmDynamicTextMessage(target.deviceID, subject, messageBody, forceRead, options);

        return res.json({
            success: result.message === "Success",
            message: result.message,
            data: [{
                ...result,
                MDM_Asset_Idn: target.MDM_Asset_Idn,
                DeviceID: target.deviceID,
                DeviceName: target.deviceName,
                PlatformType: target.platformType
            }]
        });
    } catch (err) {
        const responseData = err.response?.data || err.responseData;
        return res.status(500).json({
            success: false,
            message: "Unable to send message to this device.",
            errorMessage: getMdmErrorMessage(responseData, err.message || String(err)),
            data: [{ message: "Error", errorMessage: err.message || String(err) }]
        });
    }
}

async function handleSendMdmTextMessageByPlatformType(req, res) {
    try {
        const { subject, messageBody, forceRead, options } = extractTextMessageBody(req);
        const platformType = normalizeMdmValue(firstMdmDefined(
            req.body?.PlatformType,
            req.body?.platformType,
            req.body?.platform
        ));

        if (!platformType) {
            return res.status(400).json({ success: false, message: "PlatformType is required." });
        }

        const pool = await getSqlPoolWithRetry();
        const assets = await getMdmAssetsForTextMessage(pool, 0, platformType);
        const uniqueTargets = [];
        const seen = new Set();

        for (const asset of assets) {
            const deviceID = normalizeMdmValue(asset.DeviceID);
            if (!deviceID || seen.has(deviceID)) continue;
            seen.add(deviceID);
            uniqueTargets.push(asset);
        }

        if (uniqueTargets.length === 0) {
            return res.status(404).json({
                success: false,
                message: `No SureMDM assets found for platform '${platformType}'.`,
                data: []
            });
        }

        const responses = [];
        let SuccessCount = 0;
        let FailedCount = 0;
        let ErrorCount = 0;

        for (const asset of uniqueTargets) {
            try {
                const result = await assignSureMdmDynamicTextMessage(asset.DeviceID, subject, messageBody, forceRead, options);
                if (result.message === "Success") SuccessCount += 1;
                else if (result.message === "Failed") FailedCount += 1;
                else ErrorCount += 1;

                responses.push({
                    ...result,
                    MDM_Asset_Idn: asset.MDM_Asset_Idn,
                    DeviceID: asset.DeviceID,
                    DeviceName: asset.DeviceName,
                    PlatformType: asset.PlatformType
                });
            } catch (err) {
                ErrorCount += 1;
                responses.push({
                    message: "Error",
                    errorMessage: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err)),
                    MDM_Asset_Idn: asset.MDM_Asset_Idn,
                    DeviceID: asset.DeviceID,
                    DeviceName: asset.DeviceName,
                    PlatformType: asset.PlatformType
                });
            }
        }

        return res.json({
            success: ErrorCount === 0 && FailedCount === 0,
            message: "Broadcast message completed.",
            summary: {
                total: responses.length,
                SuccessCount,
                FailedCount,
                ErrorCount
            },
            data: responses
        });
    } catch (err) {
        const responseData = err.response?.data || err.responseData;
        return res.status(500).json({
            success: false,
            message: "Unable to broadcast message.",
            errorMessage: getMdmErrorMessage(responseData, err.message || String(err)),
            data: [{ message: "Error", errorMessage: err.message || String(err) }]
        });
    }
}

// Java-compatible endpoints
app.post("/api/mdm/SendMDMTextMessage", authenticateToken, handleSendMdmTextMessageByObject);
app.post("/api/mdm/SendMDMTextMessageNonWindows", authenticateToken, handleSendMdmTextMessageByMdmAsset);
app.post("/api/mdm/SendMDMTextMessageByPlatformType", authenticateToken, handleSendMdmTextMessageByPlatformType);

// React-friendly endpoints
app.post("/api/mdm/text-message/object", authenticateToken, handleSendMdmTextMessageByObject);
app.post("/api/mdm/text-message/device", authenticateToken, handleSendMdmTextMessageByMdmAsset);
app.post("/api/mdm/text-message/platform", authenticateToken, handleSendMdmTextMessageByPlatformType);
app.post("/api/mdm/text-message", authenticateToken, async (req, res) => {
    const objectRootIdn = parseMdmInt(firstMdmDefined(req.body?.Object_Root_Idn, req.body?.objectRootIdn, req.body?.objectRootID), 0);
    if (objectRootIdn) return handleSendMdmTextMessageByObject(req, res);
    return handleSendMdmTextMessageByMdmAsset(req, res);
});


app.use((err, req, res, next) => {
    console.error(err);
    if (res.headersSent) return next(err);
    return res.status(err.status || 500).json({
        success: false,
        message: err.message || "Internal server error"
    });
});

/*
|--------------------------------------------------------------------------
| MDM / SureMDM Remote Control API
|--------------------------------------------------------------------------
| Used by HardwareInventory.tsx Advanced Remote Control action.
| Frontend sends selected device + permission values.
| Backend resolves the proper SureMDM DeviceID and returns RemoteSupport.aspx URL.
|--------------------------------------------------------------------------
*/

function remoteNormalizeValue(value, fallback = "") {
    if (value === undefined || value === null) return fallback;
    return String(value).trim();
}

function remoteFirstDefined(...values) {
    return values.find(value => value !== undefined && value !== null && String(value).trim() !== "");
}

function remoteParseInt(value, fallback = 0) {
    const parsed = parseInt(value, 10);
    return Number.isNaN(parsed) ? fallback : parsed;
}

function remoteAsArray(payload) {
    if (!payload) return [];
    if (Array.isArray(payload)) return payload;

    if (typeof payload === "string") {
        const trimmed = payload.trim();
        if (!trimmed) return [];
        try {
            return remoteAsArray(JSON.parse(trimmed));
        } catch (_) {
            return [];
        }
    }

    if (Array.isArray(payload.rows)) return payload.rows;
    if (Array.isArray(payload.data)) return payload.data;
    if (payload.data && Array.isArray(payload.data.rows)) return payload.data.rows;

    return [payload];
}

function remoteBuildMdmHeaders(mdmConfig, options = {}) {
    const headers = { Accept: "application/json" };
    const contentType = remoteNormalizeValue(options.contentType ?? mdmConfig.contentType);
    if (contentType) headers["Content-Type"] = contentType;

    const rawToken = remoteNormalizeValue(mdmConfig.token);
    const authScheme = remoteNormalizeValue(mdmConfig.authScheme, "Basic");

    if (rawToken) {
        if (/^basic\s+/i.test(rawToken) || /^bearer\s+/i.test(rawToken)) {
            headers.Authorization = rawToken;
        } else if (rawToken.includes(":")) {
            headers.Authorization = `Basic ${Buffer.from(rawToken, "utf8").toString("base64")}`;
        } else {
            headers.Authorization = `${authScheme} ${rawToken}`;
        }
    }

    if (mdmConfig.apiKey) {
        headers[remoteNormalizeValue(mdmConfig.apiKeyHeader, "ApiKey")] = mdmConfig.apiKey;
    }

    return headers;
}

function remoteJoinMdmUrl(baseUrl, apiPath) {
    const base = remoteNormalizeValue(baseUrl).replace(/\/+$/, "");
    const path = remoteNormalizeValue(apiPath).replace(/^\/+/, "");
    if (!base) throw new Error("MDM_API.url is missing in config.ini.");
    if (!path) throw new Error("MDM API path is missing.");
    return `${base}/${path}`;
}

function remoteGetMdmErrorMessage(payload, fallback = "SureMDM request failed.") {
    if (!payload) return fallback;
    if (typeof payload === "string") return payload;
    return payload.errorMsg || payload.errorMessage || payload.message || payload.Message || fallback;
}

async function remoteCallSureMdmApi(apiPath, options = {}) {
    const mdmConfig = getMdmConfig();
    const method = remoteNormalizeValue(options.method, "GET").toUpperCase();
    const contentType = remoteNormalizeValue(options.contentType);
    const url = remoteJoinMdmUrl(mdmConfig.url, apiPath);
    const headers = remoteBuildMdmHeaders(mdmConfig, { contentType });

    const requestOptions = {
        method,
        url,
        headers,
        timeout: Number(options.timeout || mdmConfig.timeout || 60000)
    };

    if (options.data !== undefined && options.data !== null && method !== "GET") {
        requestOptions.data = options.data;
    }

    console.log("SureMDM remote-control API request:", {
        method,
        url,
        authScheme: headers.Authorization ? String(headers.Authorization).split(" ")[0] : "missing",
        hasApiKey: Boolean(headers[remoteNormalizeValue(mdmConfig.apiKeyHeader, "ApiKey")])
    });

    const response = await axios(requestOptions);
    return { data: response.data, url };
}

function remotePickSureMdmDevice(devices, match = {}) {
    const targetDeviceID = remoteNormalizeValue(match.deviceID).toLowerCase();
    const targetName = remoteNormalizeValue(match.deviceName).toLowerCase();

    if (!Array.isArray(devices) || devices.length === 0) return null;

    if (targetDeviceID) {
        const byId = devices.find(device => {
            return remoteNormalizeValue(remoteFirstDefined(device.DeviceID, device.deviceID, device.DeviceId, device.id)).toLowerCase() === targetDeviceID;
        });
        if (byId) return byId;
    }

    if (targetName) {
        const exact = devices.find(device => {
            return remoteNormalizeValue(remoteFirstDefined(device.DeviceName, device.deviceName, device.RealDeviceName, device.Hostname, device.name)).toLowerCase() === targetName;
        });
        if (exact) return exact;

        const loose = devices.find(device => {
            return remoteNormalizeValue(remoteFirstDefined(device.DeviceName, device.deviceName, device.RealDeviceName, device.Hostname, device.name)).toLowerCase().includes(targetName);
        });
        if (loose) return loose;
    }

    return devices[0];
}

async function remoteSearchSureMdmDeviceByName(deviceName, limit = 20) {
    const searchValue = remoteNormalizeValue(deviceName);
    if (!searchValue) throw new Error("DeviceName is required for SureMDM device search.");

    const payload = {
        ID: "AllDevices",
        IsSearch: true,
        Limit: limit,
        SearchColumns: ["DeviceName"],
        SearchValue: searchValue,
        SortColumn: "LastTimeStamp",
        SortOrder: "asc"
    };

    const response = await remoteCallSureMdmApi("device", {
        method: "POST",
        contentType: "application/json",
        data: payload
    });

    const devices = remoteAsArray(response.data);
    const device = remotePickSureMdmDevice(devices, { deviceName: searchValue });

    if (!device) {
        const err = new Error(`SureMDM device '${searchValue}' was not found.`);
        err.responseData = response.data;
        throw err;
    }

    return {
        device,
        devices,
        raw: response.data,
        requestUrl: response.url
    };
}

async function remoteGetMdmAssetByMdmAssetId(pool, mdmAssetIdn) {
    const result = await pool.request()
        .input("MDM_Asset_Idn", sql.Int, mdmAssetIdn)
        .query(`
            SELECT TOP 1 *
            FROM TSMDM_ASSET
            WHERE MDM_Asset_Idn = @MDM_Asset_Idn;
        `);

    return result.recordset?.[0] || null;
}

async function remoteGetMdmAssetByDeviceID(pool, deviceID) {
    const result = await pool.request()
        .input("DeviceID", sql.VarChar(255), remoteNormalizeValue(deviceID))
        .query(`
            SELECT TOP 1 *
            FROM TSMDM_ASSET
            WHERE DeviceID = @DeviceID;
        `);

    return result.recordset?.[0] || null;
}

async function remoteGetMdmAssetByObjectRoot(pool, objectRootIdn) {
    const result = await pool.request()
        .input("Object_Root_Idn", sql.Int, objectRootIdn)
        .query(`
            SELECT TOP 1
                c.*,
                b.Object_Root_Idn,
                b.Object_DeviceID AS EM_Object_DeviceID,
                b.Object_Client_Name,
                b.ComputerName,
                b.Model,
                d.BiosSerialkey
            FROM TSMDM_TS_OBJECT_MAPPING a
            LEFT JOIN TS_OBJECT_ROOT b
                ON a.Object_Root_Idn = b.Object_Root_Idn
            LEFT JOIN TSMDM_ASSET c
                ON a.MDM_Asset_Idn = c.MDM_Asset_Idn
            LEFT JOIN TS_CLIENT_INFO d
                ON a.Object_Root_Idn = d.Object_Root_Idn
            WHERE b.Object_Root_Idn = @Object_Root_Idn;
        `);

    return result.recordset?.[0] || null;
}

async function remoteGetEmFallbackCandidate(pool, objectRootIdn) {
    const result = await pool.request()
        .input("Object_Root_Idn", sql.Int, objectRootIdn)
        .query(`
            SELECT TOP 1
                r.Object_Root_Idn,
                r.Object_DeviceID AS EM_Object_DeviceID,
                r.ComputerName,
                r.Object_Client_Name,
                r.Model,
                map.MDM_Asset_Idn,
                a.DeviceID AS MDM_DeviceID,
                a.DeviceName AS MDM_DeviceName,
                a.PlatformType AS MDM_PlatformType,
                a.AgentVersion AS MDM_AgentVersion,
                a.ConnectionStatus AS MDM_ConnectionStatus
            FROM TS_OBJECT_ROOT r
            LEFT JOIN TSMDM_TS_OBJECT_MAPPING map
                ON map.Object_Root_Idn = r.Object_Root_Idn
            LEFT JOIN TSMDM_ASSET a
                ON a.MDM_Asset_Idn = map.MDM_Asset_Idn
            WHERE r.Object_Root_Idn = @Object_Root_Idn;
        `);

    return result.recordset?.[0] || null;
}

async function remoteResolveSureMdmDeviceIDFromName(deviceName) {
    const searchResult = await remoteSearchSureMdmDeviceByName(deviceName, 20);
    const selectedDevice = searchResult.device || {};

    const deviceID = remoteNormalizeValue(remoteFirstDefined(
        selectedDevice.DeviceID,
        selectedDevice.deviceID,
        selectedDevice.DeviceId,
        selectedDevice.id
    ));

    if (!deviceID) {
        throw new Error(`SureMDM device '${deviceName}' was found, but DeviceID was not returned.`);
    }

    return {
        deviceID,
        deviceName: remoteNormalizeValue(remoteFirstDefined(
            selectedDevice.DeviceName,
            selectedDevice.deviceName,
            selectedDevice.RealDeviceName,
            selectedDevice.Hostname,
            deviceName
        )),
        platformType: remoteNormalizeValue(remoteFirstDefined(
            selectedDevice.PlatformType,
            selectedDevice.platformType,
            selectedDevice.Platform,
            selectedDevice.platform
        )),
        agentVersion: remoteNormalizeValue(remoteFirstDefined(
            selectedDevice.AgentVersion,
            selectedDevice.agentVersion,
            selectedDevice.AgentVer,
            selectedDevice.agentver
        )),
        selectedDevice,
        raw: searchResult.raw
    };
}

async function remoteResolveTarget(pool, body = {}) {
    const objectAgent = remoteNormalizeValue(remoteFirstDefined(
        body.objectAgent,
        body.Object_Agent,
        body.agent
    ), "EM").toUpperCase();

    const objectRootIdn = remoteParseInt(remoteFirstDefined(
        body.Object_Root_Idn,
        body.objectRootIdn,
        body.objectRootID,
        objectAgent === "EM" ? body.assetId : undefined
    ), 0);

    const mdmAssetIdn = remoteParseInt(remoteFirstDefined(
        body.MDM_Asset_Idn,
        body.mdmAssetIdn,
        body.mdmAssetID,
        objectAgent === "MDM" ? body.assetId : undefined
    ), 0);

    const requestedDeviceID = remoteNormalizeValue(remoteFirstDefined(
        body.MDM_DeviceID,
        body.mdmDeviceID,
        body.DeviceID,
        body.deviceID,
        body.deviceId,
        objectAgent === "MDM" ? body.Object_DeviceID : undefined,
        objectAgent === "MDM" ? body.objectDeviceID : undefined
    ));

    const requestedDeviceName = remoteNormalizeValue(remoteFirstDefined(
        body.DeviceName,
        body.deviceName,
        body.ComputerName,
        body.computerName
    ));

    let localAsset = null;

    if (objectAgent === "EM" && objectRootIdn) {
        localAsset = await remoteGetMdmAssetByObjectRoot(pool, objectRootIdn);
        if (!localAsset) localAsset = await remoteGetEmFallbackCandidate(pool, objectRootIdn);
    }

    if (!localAsset && mdmAssetIdn) {
        localAsset = await remoteGetMdmAssetByMdmAssetId(pool, mdmAssetIdn);
    }

    if (!localAsset && requestedDeviceID) {
        localAsset = await remoteGetMdmAssetByDeviceID(pool, requestedDeviceID);
    }

    let deviceID = remoteNormalizeValue(remoteFirstDefined(
        localAsset?.DeviceID,
        localAsset?.MDM_DeviceID,
        requestedDeviceID
    ));

    let deviceName = remoteNormalizeValue(remoteFirstDefined(
        localAsset?.DeviceName,
        localAsset?.MDM_DeviceName,
        localAsset?.ComputerName,
        localAsset?.Object_Client_Name,
        requestedDeviceName
    ));

    let platformType = remoteNormalizeValue(remoteFirstDefined(
        localAsset?.PlatformType,
        localAsset?.MDM_PlatformType,
        body.PlatformType,
        body.platformType,
        "Windows"
    ));

    let agentVersion = remoteNormalizeValue(remoteFirstDefined(
        localAsset?.AgentVersion,
        localAsset?.MDM_AgentVersion,
        body.AgentVersion,
        body.agentVersion
    ));

    let sureMdmLookup = null;

    if (!deviceID && deviceName) {
        sureMdmLookup = await remoteResolveSureMdmDeviceIDFromName(deviceName);
        deviceID = sureMdmLookup.deviceID;
        deviceName = sureMdmLookup.deviceName || deviceName;
        platformType = platformType || sureMdmLookup.platformType || "Windows";
        agentVersion = agentVersion || sureMdmLookup.agentVersion;
    }

    if (!deviceID) {
        throw new Error("Could not resolve SureMDM DeviceID for this device.");
    }

    return {
        objectAgent,
        Object_Root_Idn: objectRootIdn,
        MDM_Asset_Idn: mdmAssetIdn || localAsset?.MDM_Asset_Idn || 0,
        deviceID,
        deviceName,
        platformType: platformType || "Windows",
        agentVersion,
        localAsset,
        sureMdmLookup
    };
}

function remoteNormalizePermissions(body = {}) {
    const allowed = new Set([126, 127, 128, 129]);
    const fromArray = Array.isArray(body.permissions) ? body.permissions : [];
    const fromString = remoteNormalizeValue(body.perm || body.Permission || body.permissionsCsv)
        .split(",")
        .map(value => value.trim())
        .filter(Boolean);

    const merged = [...fromArray, ...fromString]
        .map(value => parseInt(value, 10))
        .filter(value => allowed.has(value));

    const unique = Array.from(new Set(merged));

    if (unique.length === 0) return [126, 127, 128, 129];

    return unique.sort((a, b) => a - b);
}

function remoteGetPortalBaseUrl() {
    const mdmConfig = getMdmConfig();
    const rawUrl = remoteNormalizeValue(mdmConfig.portalUrl || mdmConfig.webUrl || mdmConfig.baseUrl || mdmConfig.url);

    if (!rawUrl) throw new Error("MDM portal URL is missing in config.ini.");

    try {
        const parsed = new URL(rawUrl);
        return `${parsed.protocol}//${parsed.host}`;
    } catch (_) {
        return rawUrl.replace(/\/+$/, "");
    }
}

function remoteBuildSupportUrl(target, permissions) {
    const baseUrl = remoteGetPortalBaseUrl();
    const params = new URLSearchParams();

    params.set("id", target.deviceID);
    params.set("name", target.deviceName || target.deviceID);
    params.set("pltFrmType", target.platformType || "Windows");
    if (target.agentVersion) params.set("agentversion", target.agentVersion);
    params.set("perm", permissions.join(","));

    return `${baseUrl}/RemoteSupport.aspx?${params.toString()}`;
}

// Legacy RemoteSupport.aspx route kept for fallback only. Do not use for Hardware Inventory Advanced Remote Control.
app.post("/api/mdm/remote-control-legacy", authenticateToken, async (req, res) => {
    try {
        const pool = await sql.connect(dbConfig);
        const target = await remoteResolveTarget(pool, req.body || {});
        const permissions = remoteNormalizePermissions(req.body || {});
        const url = remoteBuildSupportUrl(target, permissions);

        return res.json({
            success: true,
            message: "Success",
            data: [{
                message: "Success",
                url,
                method: "documented-remote-support",
                objectAgent: target.objectAgent,
                Object_Root_Idn: target.Object_Root_Idn,
                MDM_Asset_Idn: target.MDM_Asset_Idn,
                deviceID: target.deviceID,
                deviceName: target.deviceName,
                platformType: target.platformType,
                agentVersion: target.agentVersion,
                permissions,
                perm: permissions.join(",")
            }]
        });
    } catch (err) {
        const responseData = err.response?.data || err.responseData;
        return res.status(500).json({
            success: false,
            message: "Unable to start remote-control session.",
            errorMessage: remoteGetMdmErrorMessage(responseData, err.message || String(err)),
            data: []
        });
    }
});


/*
|--------------------------------------------------------------------------
| MDM / SureMDM iframe remote-control APIs
|--------------------------------------------------------------------------
| Uses SureMDM iframeRS/rsauthtoken flow and returns a temporary
| IframeRemoteSupport.aspx?AuthToken=... URL to the frontend.
| Paste this block before the error-handler / START SERVER section.
|--------------------------------------------------------------------------
*/

function rcNormalize(value, fallback = "") {
    if (value === undefined || value === null) return fallback;
    return String(value).trim();
}

function rcParseInt(value, fallback = 0) {
    const parsed = parseInt(value, 10);
    return Number.isNaN(parsed) ? fallback : parsed;
}

function rcFirstDefined(...values) {
    return values.find(value => value !== undefined && value !== null && String(value).trim() !== "");
}

function rcParseBoolean(value, fallback = false) {
    if (value === undefined || value === null || value === "") return fallback;
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value !== 0;

    const text = String(value).trim().toLowerCase();
    if (["true", "1", "yes", "y", "on"].includes(text)) return true;
    if (["false", "0", "no", "n", "off"].includes(text)) return false;
    return fallback;
}

function rcNormalizeRemoteParam(value, fallback = "null") {
    const text = rcNormalize(value);
    return text || fallback;
}

function rcCleanApiPath(apiPath, baseUrl = "") {
    let clean = rcNormalize(apiPath).replace(/^\/+/, "");
    const base = rcNormalize(baseUrl).replace(/\/+$/, "").toLowerCase();

    // Avoid https://tenant/api/api/... only when base URL already ends with /api.
    if (base.endsWith("/api") && clean.toLowerCase().startsWith("api/")) {
        clean = clean.slice(4);
    }

    return clean;
}

async function rcGetSqlPoolWithRetry() {
    try {
        return await sql.connect(dbConfig);
    } catch (err) {
        console.warn("SQL connect failed. Retrying with a fresh pool:", err.message || err);
        try { await sql.close(); } catch (_) {}
        return await sql.connect(dbConfig);
    }
}

function rcBuildMdmHeaders(mdmConfig, options = {}) {
    const headers = { Accept: "application/json" };
    const contentType = rcNormalize(options.contentType ?? mdmConfig.contentType);
    if (contentType) headers["Content-Type"] = contentType;

    const rawToken = rcNormalize(mdmConfig.token);
    const authScheme = rcNormalize(mdmConfig.authScheme, "Basic");

    if (rawToken) {
        if (/^basic\s+/i.test(rawToken) || /^bearer\s+/i.test(rawToken)) {
            headers.Authorization = rawToken;
        } else if (rawToken.includes(":")) {
            headers.Authorization = `Basic ${Buffer.from(rawToken, "utf8").toString("base64")}`;
        } else {
            headers.Authorization = `${authScheme} ${rawToken}`;
        }
    }

    if (mdmConfig.apiKey) {
        headers[rcNormalize(mdmConfig.apiKeyHeader, "ApiKey")] = mdmConfig.apiKey;
    }

    return headers;
}

function rcJoinMdmUrl(baseUrl, apiPath) {
    const base = rcNormalize(baseUrl).replace(/\/+$/, "");
    const path = rcCleanApiPath(apiPath, baseUrl);
    if (!base) throw new Error("MDM_API.url is missing in config.ini.");
    if (!path) throw new Error("MDM API path is missing.");
    return `${base}/${path}`;
}

function rcGetMdmErrorMessage(payload, fallback = "SureMDM request failed.") {
    if (!payload) return fallback;
    if (typeof payload === "string") return payload;
    return payload.errorMsg || payload.ErrorMsg || payload.errorMessage || payload.message || payload.Message || fallback;
}

function rcAsSureMdmArray(payload) {
    if (!payload) return [];
    if (Array.isArray(payload)) return payload;

    if (typeof payload === "string") {
        const trimmed = payload.trim();
        if (!trimmed) return [];
        try {
            return rcAsSureMdmArray(JSON.parse(trimmed));
        } catch (_) {
            return [];
        }
    }

    if (Array.isArray(payload.rows)) return payload.rows;
    if (Array.isArray(payload.data)) return payload.data;
    if (payload.data && Array.isArray(payload.data.rows)) return payload.data.rows;

    return [payload];
}

function rcPickSureMdmDevice(devices, match = {}) {
    const targetDeviceID = rcNormalize(match.deviceID).toLowerCase();
    const targetName = rcNormalize(match.deviceName).toLowerCase();

    if (!Array.isArray(devices) || devices.length === 0) return null;

    if (targetDeviceID) {
        const byId = devices.find(device => {
            return rcNormalize(rcFirstDefined(device.DeviceID, device.deviceID, device.DeviceId, device.id)).toLowerCase() === targetDeviceID;
        });
        if (byId) return byId;
    }

    if (targetName) {
        const exact = devices.find(device => {
            return rcNormalize(rcFirstDefined(device.DeviceName, device.deviceName, device.RealDeviceName, device.Hostname, device.name)).toLowerCase() === targetName;
        });
        if (exact) return exact;

        const loose = devices.find(device => {
            return rcNormalize(rcFirstDefined(device.DeviceName, device.deviceName, device.RealDeviceName, device.Hostname, device.name)).toLowerCase().includes(targetName);
        });
        if (loose) return loose;
    }

    return devices[0];
}

async function rcCallSureMdmApi(apiPath, options = {}) {
    const mdmConfig = getMdmConfig();
    const method = rcNormalize(options.method, "GET").toUpperCase();
    const contentType = rcNormalize(options.contentType);
    const url = rcJoinMdmUrl(mdmConfig.url, apiPath);
    const headers = rcBuildMdmHeaders(mdmConfig, { contentType });

    const requestOptions = {
        method,
        url,
        headers,
        timeout: Number(options.timeout || mdmConfig.remoteControlTimeout || mdmConfig.timeout || 60000)
    };

    if (options.data !== undefined && options.data !== null && method !== "GET") {
        requestOptions.data = options.data;
    }

    console.log("SureMDM remote-control API request:", {
        method,
        url,
        authScheme: headers.Authorization ? String(headers.Authorization).split(" ")[0] : "missing",
        hasApiKey: Boolean(headers[rcNormalize(mdmConfig.apiKeyHeader, "ApiKey")])
    });

    const response = await axios(requestOptions);
    return { data: response.data, url };
}

async function rcSearchSureMdmDeviceByName(deviceName, limit = 20) {
    const searchValue = rcNormalize(deviceName);
    if (!searchValue) throw new Error("DeviceName is required for SureMDM device search.");

    const payload = {
        ID: "AllDevices",
        IsSearch: true,
        Limit: limit,
        SearchColumns: ["DeviceName"],
        SearchValue: searchValue,
        SortColumn: "LastTimeStamp",
        SortOrder: "asc"
    };

    const response = await rcCallSureMdmApi("device", {
        method: "POST",
        contentType: "application/json",
        data: payload
    });

    const devices = rcAsSureMdmArray(response.data);
    const device = rcPickSureMdmDevice(devices, { deviceName: searchValue });

    if (!device) {
        const err = new Error(`SureMDM device '${searchValue}' was not found.`);
        err.responseData = response.data;
        throw err;
    }

    return {
        device,
        devices,
        raw: response.data,
        requestUrl: response.url
    };
}

async function rcGetSureMdmDeviceDetails(deviceID) {
    const id = rcNormalize(deviceID);
    if (!id) throw new Error("DeviceID is required for SureMDM device details.");

    const response = await rcCallSureMdmApi(`device/${encodeURIComponent(id)}`, {
        method: "GET",
        contentType: "application/json"
    });

    const devices = rcAsSureMdmArray(response.data);
    const device = rcPickSureMdmDevice(devices, { deviceID: id }) || devices[0];

    if (!device) {
        const err = new Error(`SureMDM device details were not found for DeviceID '${id}'.`);
        err.responseData = response.data;
        throw err;
    }

    return {
        device,
        raw: response.data,
        requestUrl: response.url
    };
}

function rcGetIframeRemoteOptions(body = {}) {
    const mdmConfig = getMdmConfig();

    return {
        ShowOnlyRemoteScreen: rcParseBoolean(rcFirstDefined(
            body.ShowOnlyRemoteScreen,
            body.showOnlyRemoteScreen,
            body.onlyRemoteScreen,
            mdmConfig.showOnlyRemoteScreen,
            mdmConfig.remoteSupportShowOnlyRemoteScreen
        ), false),
        ScrBgClr: rcNormalizeRemoteParam(rcFirstDefined(
            body.ScrBgClr,
            body.scrBgClr,
            body.screenBackgroundColor,
            mdmConfig.ScrBgClr,
            mdmConfig.scrBgClr,
            mdmConfig.remoteSupportScrBgClr
        ), "null"),
        ScrImg: rcNormalizeRemoteParam(rcFirstDefined(
            body.ScrImg,
            body.scrImg,
            body.screenImage,
            mdmConfig.ScrImg,
            mdmConfig.scrImg,
            mdmConfig.remoteSupportScrImg
        ), "null")
    };
}

async function rcGenerateIframeRemoteSupportUrl(deviceID, options = {}) {
    const sureMdmDeviceID = rcNormalize(deviceID);
    if (!sureMdmDeviceID) throw new Error("SureMDM DeviceID is required for iframe remote support.");

    const mdmConfig = getMdmConfig();
    const remoteControlPath = rcNormalize(mdmConfig.remoteControlPath, "iframeRS/rsauthtoken");
    const iframeOptions = {
        ShowOnlyRemoteScreen: rcParseBoolean(options.ShowOnlyRemoteScreen, false),
        ScrBgClr: rcNormalizeRemoteParam(options.ScrBgClr, "null"),
        ScrImg: rcNormalizeRemoteParam(options.ScrImg, "null")
    };

    const params = new URLSearchParams({
        ShowOnlyRemoteScreen: String(iframeOptions.ShowOnlyRemoteScreen),
        deviceid: sureMdmDeviceID,
        ScrBgClr: iframeOptions.ScrBgClr,
        ScrImg: iframeOptions.ScrImg
    });

    const response = await rcCallSureMdmApi(`${remoteControlPath}?${params.toString()}`, {
        method: "GET",
        contentType: ""
    });

    let payload = response.data;
    if (typeof payload === "string") {
        const trimmed = payload.trim();
        try {
            payload = trimmed ? JSON.parse(trimmed) : {};
        } catch (_) {
            payload = { data: trimmed, isSuccess: Boolean(trimmed), errorMsg: "" };
        }
    }

    const isSuccess = payload?.isSuccess ?? payload?.IsSuccess ?? payload?.success ?? payload?.Success;
    const remoteUrl = rcNormalize(rcFirstDefined(
        payload?.data,
        payload?.Data,
        payload?.url,
        payload?.Url,
        payload?.URL
    ));

    if (isSuccess === false) {
        const err = new Error(rcGetMdmErrorMessage(payload, "SureMDM iframe remote support token generation failed."));
        err.responseData = payload;
        throw err;
    }

    if (!remoteUrl) {
        const err = new Error("SureMDM iframe remote support URL was not returned.");
        err.responseData = payload;
        throw err;
    }

    return {
        url: remoteUrl,
        requestUrl: response.url,
        raw: payload,
        options: iframeOptions,
        tokenExpiresInSeconds: 300
    };
}

async function rcGetEmRemoteControlCandidate(pool, objectRootIdn) {
    const result = await pool.request()
        .input("Object_Root_Idn", sql.Int, objectRootIdn)
        .query(`
            SELECT TOP 1
                r.Object_Root_Idn,
                r.Object_DeviceID AS EM_Object_DeviceID,
                r.ComputerName,
                r.Object_Client_Name,
                r.Model,
                map.MDM_Asset_Idn,
                a.DeviceID AS MDM_DeviceID,
                a.DeviceName AS MDM_DeviceName,
                a.PlatformType AS MDM_PlatformType,
                a.AgentVersion AS MDM_AgentVersion,
                a.ConnectionStatus AS MDM_ConnectionStatus
            FROM TS_OBJECT_ROOT r
            LEFT JOIN TSMDM_TS_OBJECT_MAPPING map
                ON map.Object_Root_Idn = r.Object_Root_Idn
            LEFT JOIN TSMDM_ASSET a
                ON a.MDM_Asset_Idn = map.MDM_Asset_Idn
            WHERE r.Object_Root_Idn = @Object_Root_Idn;
        `);

    return result.recordset?.[0] || null;
}

async function rcGetMdmAssetByMdmAssetId(pool, mdmAssetIdn) {
    const result = await pool.request()
        .input("MDM_Asset_Idn", sql.Int, mdmAssetIdn)
        .query(`
            SELECT TOP 1 *
            FROM TSMDM_ASSET
            WHERE MDM_Asset_Idn = @MDM_Asset_Idn;
        `);

    return result.recordset?.[0] || null;
}

async function rcGetMdmAssetByDeviceID(pool, deviceID) {
    const result = await pool.request()
        .input("DeviceID", sql.VarChar(255), rcNormalize(deviceID))
        .query(`
            SELECT TOP 1 *
            FROM TSMDM_ASSET
            WHERE DeviceID = @DeviceID;
        `);

    return result.recordset?.[0] || null;
}

async function rcGetMdmAssets(pool, mdmAssetIdn = 0, platformType = "") {
    const result = await pool.request()
        .input("MDM_Asset_Idn", sql.Int, mdmAssetIdn)
        .input("PlatformType", sql.VarChar(255), rcNormalize(platformType))
        .query(`
            SELECT *,
                   CASE WHEN DeviceLocalIPAddress IS NULL OR DeviceLocalIPAddress = ''
                        THEN DeviceIPAddress ELSE DeviceLocalIPAddress END AS IPAddress
            FROM TSMDM_ASSET
            WHERE (@MDM_Asset_Idn = 0 OR MDM_Asset_Idn = @MDM_Asset_Idn)
              AND (@PlatformType = '' OR PlatformType LIKE @PlatformType + '%')
            ORDER BY DeviceName ASC;
        `);

    return result.recordset || [];
}

async function rcResolveRemoteControlTarget(req, mode = "auto") {
    const body = req.body || {};
    const pool = await rcGetSqlPoolWithRetry();

    const objectAgent = rcNormalize(rcFirstDefined(
        body.objectAgent,
        body.Object_Agent,
        body.agent
    ), mode === "mdm" ? "MDM" : "EM").toUpperCase();

    const objectRootIdn = rcParseInt(rcFirstDefined(
        body.Object_Root_Idn,
        body.objectRootIdn,
        body.objectRootID,
        (objectAgent === "EM" || mode === "object") ? body.assetId : undefined
    ), 0);

    const mdmAssetIdn = rcParseInt(rcFirstDefined(
        body.MDM_Asset_Idn,
        body.mdmAssetIdn,
        body.mdmAssetID,
        (objectAgent === "MDM" || mode === "mdm") ? body.assetId : undefined
    ), 0);

    // For EM/TCO rows, Object_DeviceID is not the SureMDM DeviceID.
    // Only use raw DeviceID directly for MDM mode.
    const requestedDeviceID = rcNormalize(rcFirstDefined(
        body.MDM_DeviceID,
        body.mdmDeviceID,
        body.DeviceID,
        body.deviceID,
        body.deviceId,
        objectAgent === "MDM" ? body.Object_DeviceID : undefined,
        objectAgent === "MDM" ? body.objectDeviceID : undefined
    ));

    const requestedDeviceName = rcNormalize(rcFirstDefined(
        body.DeviceName,
        body.deviceName,
        body.ComputerName,
        body.computerName
    ));

    let localAsset = null;
    let deviceID = "";
    let deviceName = "";

    if (objectAgent === "EM" || mode === "object") {
        if (!objectRootIdn && !requestedDeviceName) {
            throw new Error("Object_Root_Idn, assetId, or DeviceName is required for EM remote control.");
        }

        if (objectRootIdn) {
            localAsset = await rcGetEmRemoteControlCandidate(pool, objectRootIdn);
        }

        if (!localAsset && !requestedDeviceName) {
            throw new Error(`EM asset was not found for Object_Root_Idn '${objectRootIdn}'.`);
        }

        deviceName = rcNormalize(rcFirstDefined(
            requestedDeviceName,
            localAsset?.MDM_DeviceName,
            localAsset?.ComputerName,
            localAsset?.Object_Client_Name
        ));
        deviceID = rcNormalize(localAsset?.MDM_DeviceID);
    } else if (objectAgent === "MDM" || mode === "mdm") {
        if (mdmAssetIdn) {
            localAsset = await rcGetMdmAssetByMdmAssetId(pool, mdmAssetIdn);
        }

        if (!localAsset && requestedDeviceID) {
            localAsset = await rcGetMdmAssetByDeviceID(pool, requestedDeviceID);
        }

        deviceID = rcNormalize(rcFirstDefined(localAsset?.DeviceID, requestedDeviceID));
        deviceName = rcNormalize(rcFirstDefined(localAsset?.DeviceName, requestedDeviceName));
    } else {
        throw new Error(`Unsupported objectAgent '${objectAgent}'.`);
    }

    if (!deviceID && !deviceName) {
        throw new Error("Could not resolve a SureMDM DeviceID or DeviceName for remote control.");
    }

    return {
        objectAgent,
        objectRootIdn,
        mdmAssetIdn: mdmAssetIdn || localAsset?.MDM_Asset_Idn || 0,
        deviceID,
        deviceName,
        localAsset
    };
}

async function rcCreateSureMdmRemoteSupportSession(target, options = {}) {
    let searchResult = null;
    let selectedDevice = null;
    let sureMdmDeviceID = rcNormalize(target.deviceID);

    if (!sureMdmDeviceID) {
        searchResult = await rcSearchSureMdmDeviceByName(target.deviceName);
        selectedDevice = searchResult.device;

        sureMdmDeviceID = rcNormalize(rcFirstDefined(
            selectedDevice.DeviceID,
            selectedDevice.deviceID,
            selectedDevice.DeviceId,
            selectedDevice.id
        ));

        if (!sureMdmDeviceID) {
            throw new Error(`SureMDM search found '${target.deviceName}', but the result did not contain DeviceID.`);
        }
    } else {
        selectedDevice = {
            DeviceID: sureMdmDeviceID,
            DeviceName: target.deviceName,
            PlatformType: rcFirstDefined(target.localAsset?.PlatformType, target.localAsset?.MDM_PlatformType),
            AgentVersion: rcFirstDefined(target.localAsset?.AgentVersion, target.localAsset?.MDM_AgentVersion)
        };
    }

    const iframeResult = await rcGenerateIframeRemoteSupportUrl(sureMdmDeviceID, options);

    return {
        url: iframeResult.url,
        selectedDevice,
        searchRaw: searchResult?.raw || null,
        iframeRaw: iframeResult.raw,
        iframeRequestUrl: iframeResult.requestUrl,
        iframeOptions: iframeResult.options,
        tokenExpiresInSeconds: iframeResult.tokenExpiresInSeconds,
        method: "iframe-remote-support"
    };
}

async function rcHandleMdmRemoteControl(req, res, mode = "auto") {
    try {
        const target = await rcResolveRemoteControlTarget(req, mode);

        console.log("Remote control resolved local target:", {
            objectAgent: target.objectAgent,
            Object_Root_Idn: target.objectRootIdn || undefined,
            MDM_Asset_Idn: target.mdmAssetIdn || undefined,
            deviceID: target.deviceID || undefined,
            deviceName: target.deviceName || undefined
        });

        const remoteOptions = rcGetIframeRemoteOptions(req.body || {});
        const remoteResult = await rcCreateSureMdmRemoteSupportSession(target, remoteOptions);
        const selectedDevice = remoteResult.selectedDevice || {};

        return res.json({
            success: true,
            data: [{
                message: "Success",
                url: remoteResult.url,
                method: remoteResult.method,
                objectAgent: target.objectAgent,
                Object_Root_Idn: target.objectRootIdn || undefined,
                MDM_Asset_Idn: target.mdmAssetIdn || undefined,
                deviceID: rcNormalize(rcFirstDefined(selectedDevice.DeviceID, target.deviceID)),
                deviceName: rcNormalize(rcFirstDefined(selectedDevice.DeviceName, target.deviceName)),
                platformType: rcNormalize(rcFirstDefined(selectedDevice.PlatformType, selectedDevice.platformType)),
                agentVersion: rcNormalize(rcFirstDefined(selectedDevice.AgentVersion, selectedDevice.agentVersion, selectedDevice.AgentFormatVersion)),
                iframeOptions: remoteResult.iframeOptions,
                tokenExpiresInSeconds: remoteResult.tokenExpiresInSeconds
            }]
        });
    } catch (err) {
        const responseData = err.responseData || err.response?.data;
        const message = rcGetMdmErrorMessage(responseData, err.message || String(err));

        console.error("MDM remote control failed:", responseData || err);

        return res.status(500).json({
            success: false,
            message: "Failed to start remote control session.",
            errorMessage: message,
            data: [{ message, url: "" }]
        });
    }
}

