let networkDeviceStatusRows = [
    { id: 1, deviceName: "PX3000 Archer", deviceBrand: "ASUS", deviceStatus: "Active", deviceVersion: "V2.0", location: "Administrator", purpose: "Router", patchDate: "2021-05-21", remarks: "-" },
    { id: 2, deviceName: "PX1500 Javelin", deviceBrand: "ASUS", deviceStatus: "Active", deviceVersion: "V1.0", location: "Workgroup", purpose: "Router", patchDate: "2021-09-21", remarks: "-" },
    { id: 3, deviceName: "PS1000 Spear", deviceBrand: "ASUS", deviceStatus: "Active", deviceVersion: "V2.0", location: "User-Management", purpose: "Router", patchDate: "2021-11-21", remarks: "-" }
];

app.get("/api/network/network-device-status", authenticateToken, async (req, res) => {
    try {
        const search = normalizeNetworkValue(req.query.search || req.query.q).toLowerCase();
        let data = networkDeviceStatusRows;

        if (search) {
            data = data.filter(row => Object.values(row).some(value => String(value).toLowerCase().includes(search)));
        }

        const paged = paginateRows(data, req);
        return res.json({ success: true, ...paged });
    } catch (err) {
        console.error(err);
        return res.status(500).json({ success: false, message: "Failed to retrieve network device status list" });
    }
});

app.post("/api/network/network-device-status", authenticateToken, async (req, res) => {
    try {
        const nextID = networkDeviceStatusRows.length
            ? Math.max(...networkDeviceStatusRows.map(row => row.id)) + 1
            : 1;

        const row = {
            id: nextID,
            deviceName: normalizeNetworkValue(req.body.deviceName),
            deviceBrand: normalizeNetworkValue(req.body.deviceBrand),
            deviceStatus: normalizeNetworkValue(req.body.deviceStatus, "Active"),
            deviceVersion: normalizeNetworkValue(req.body.deviceVersion),
            location: normalizeNetworkValue(req.body.location),
            purpose: normalizeNetworkValue(req.body.purpose),
            patchDate: normalizeNetworkValue(req.body.patchDate),
            remarks: normalizeNetworkValue(req.body.remarks, "-")
        };

        if (!row.deviceName) {
            return res.status(400).json({ success: false, message: "deviceName is required" });
        }

        networkDeviceStatusRows.push(row);
        return res.status(201).json({ success: true, data: row });
    } catch (err) {
        console.error(err);
        return res.status(500).json({ success: false, message: "Failed to add network device status" });
    }
});

app.put("/api/network/network-device-status/:id", authenticateToken, async (req, res) => {
    try {
        const id = parseNetworkInt(req.params.id, 0);
        const index = networkDeviceStatusRows.findIndex(row => row.id === id);

        if (index === -1) {
            return res.status(404).json({ success: false, message: "Network device not found" });
        }

        networkDeviceStatusRows[index] = {
            ...networkDeviceStatusRows[index],
            ...["deviceName", "deviceBrand", "deviceStatus", "deviceVersion", "location", "purpose", "patchDate", "remarks"].reduce((acc, key) => {
                if (req.body[key] !== undefined) acc[key] = normalizeNetworkValue(req.body[key]);
                return acc;
            }, {})
        };

        return res.json({ success: true, data: networkDeviceStatusRows[index] });
    } catch (err) {
        console.error(err);
        return res.status(500).json({ success: false, message: "Failed to update network device status" });
    }
});

app.delete("/api/network/network-device-status/:id", authenticateToken, async (req, res) => {
    try {
        const id = parseNetworkInt(req.params.id, 0);
        const before = networkDeviceStatusRows.length;
        networkDeviceStatusRows = networkDeviceStatusRows.filter(row => row.id !== id);

        if (networkDeviceStatusRows.length === before) {
            return res.status(404).json({ success: false, message: "Network device not found" });
        }

        return res.json({ success: true, message: "Network device removed" });
    } catch (err) {
        console.error(err);
        return res.status(500).json({ success: false, message: "Failed to delete network device status" });
    }
});

