      findings: [`${d.appMeteringRows.length} metering-related job(s) were found.`, `${d.appMeteringRows.filter((j) => Number(j.statusCode) === 2202).length} metering job(s) completed.`],
      conclusion: "Metering results should be compared with software inventory before usage decisions."
