// GET /api/settings/device-pricing/categories
app.get("/api/settings/device-pricing/categories", authenticateToken, async (req, res) => {
    try {
        const pool = await sql.connect(dbConfig);

        const result = await pool.request().query(`
            WITH DeviceBase AS (
                ${apUnifiedDeviceBaseSql()}
            ),
            DeviceCategoryResult AS (
                SELECT ${AP_DEVICE_CATEGORY_CASE_SQL} AS DeviceCategory
                FROM DeviceBase
            )
            SELECT DISTINCT DeviceCategory
            FROM DeviceCategoryResult
            WHERE DeviceCategory IS NOT NULL
              AND LTRIM(RTRIM(DeviceCategory)) <> ''
            ORDER BY DeviceCategory;
        `);

        return res.json((result.recordset || []).map((row) => row.DeviceCategory));
    } catch (err) {
        console.error("GET /api/settings/device-pricing/categories error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to fetch device pricing categories.",
            error: err.message
        });
    }
});

