async function apBulkSavePricingHandler(req, res) {
    const rows = Array.isArray(req.body)
        ? req.body
        : Array.isArray(req.body?.pricing)
            ? req.body.pricing
            : Array.isArray(req.body?.data)
                ? req.body.data
                : [];

    if (!Array.isArray(rows)) {
        return res.status(400).json({
            success: false,
            message: "Pricing payload must be an array."
        });
    }

    let transaction;

    try {
        const pool = await sql.connect(dbConfig);
        transaction = new sql.Transaction(pool);
        await transaction.begin();

        await new sql.Request(transaction).query(`DELETE FROM AssetPricing;`);

        for (const rawRow of rows) {
            const row = apReadPricingPayload(rawRow);

            await new sql.Request(transaction)
                .input("Category", sql.NVarChar(100), row.Category)
                .input("Brand", sql.NVarChar(150), row.Brand)
                .input("Model", sql.NVarChar(200), row.Model)
                .input("Price", sql.Decimal(18, 2), row.Price)
                .input("IsExcluded", sql.Bit, row.IsExcluded ? 1 : 0)
                .query(`
                    INSERT INTO AssetPricing
                    (
                        Category,
                        Brand,
                        Model,
                        Price,
                        IsExcluded,
                        CreatedAt,
                        UpdatedAt
                    )
                    VALUES
                    (
                        @Category,
                        @Brand,
                        @Model,
                        @Price,
                        @IsExcluded,
                        GETDATE(),
                        GETDATE()
                    );
                `);
        }

        await transaction.commit();
        transaction = null;

        await logEmaAudit(
            pool,
            req,
            "Bulk updated device pricing rules",
            "Device Pricing",
            "Success",
            {
                totalRecords: rows.length,
                source: "bulk-save",
                sampleRows: rows.slice(0, 10).map((item) => sanitizeAuditDetails(apReadPricingPayload(item)))
            },
            { entityType: "DevicePricing", entityID: "bulk" }
        );

        return res.json({
            success: true,
            message: "Device pricing saved successfully.",
            totalRecords: rows.length
        });
    } catch (err) {
        if (transaction) {
            try {
                await transaction.rollback();
            } catch (rollbackErr) {
                console.error("Device pricing rollback failed:", rollbackErr);
            }
        }

        console.error("POST device pricing bulk save error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to save device pricing.",
            error: err.message
        });
    }
}

