// POST /api/settings/device-pricing/row
// If PricingID exists, it updates. If not, it creates a new row.
app.post("/api/settings/device-pricing/row", authenticateToken, async (req, res) => {
    try {
        const row = apReadPricingPayload(req.body || {});
        const pool = await sql.connect(dbConfig);

        if (row.PricingID > 0) {
            const beforeResult = await pool.request()
                .input("PricingID", sql.Int, row.PricingID)
                .query(`
                    SELECT TOP 1 *
                    FROM AssetPricing WITH (NOLOCK)
                    WHERE PricingID = @PricingID;
                `);
            const beforeRow = beforeResult.recordset?.[0] || null;

            const updateResult = await pool.request()
                .input("PricingID", sql.Int, row.PricingID)
                .input("Category", sql.NVarChar(100), row.Category)
                .input("Brand", sql.NVarChar(150), row.Brand)
                .input("Model", sql.NVarChar(200), row.Model)
                .input("Price", sql.Decimal(18, 2), row.Price)
                .input("IsExcluded", sql.Bit, row.IsExcluded ? 1 : 0)
                .query(`
                    UPDATE AssetPricing
                    SET
                        Category = @Category,
                        Brand = @Brand,
                        Model = @Model,
                        Price = @Price,
                        IsExcluded = @IsExcluded,
                        UpdatedAt = GETDATE()
                    OUTPUT INSERTED.*
                    WHERE PricingID = @PricingID;
                `);

            if (!updateResult.recordset || updateResult.recordset.length === 0) {
                return res.status(404).json({
                    success: false,
                    message: "Device pricing row was not found."
                });
            }

            const data = apNormalizePricingRow(updateResult.recordset[0]);
            await logEmaAudit(
                pool,
                req,
                buildPricingAuditAction("update", beforeRow, data),
                "Device Pricing",
                "Success",
                {
                    before: beforeRow ? apNormalizePricingRow(beforeRow) : null,
                    after: data,
                    changes: buildAuditChangedFields(beforeRow ? apNormalizePricingRow(beforeRow) : {}, data)
                },
                { entityType: "DevicePricing", entityID: String(data.PricingID || row.PricingID) }
            );

            return res.json({
                success: true,
                message: "Device pricing updated successfully.",
                data
            });
        }

        const insertResult = await pool.request()
            .input("Category", sql.NVarChar(100), row.Category)
            .input("Brand", sql.NVarChar(150), row.Brand)
            .input("Model", sql.NVarChar(200), row.Model)
            .input("Price", sql.Decimal(18, 2), row.Price)
            .input("IsExcluded", sql.Bit, row.IsExcluded ? 1 : 0)
            .query(`
                INSERT INTO AssetPricing
                (
                    Category,
                    Brand,
                    Model,
                    Price,
                    IsExcluded,
                    CreatedAt,
                    UpdatedAt
                )
                OUTPUT INSERTED.*
                VALUES
                (
                    @Category,
                    @Brand,
                    @Model,
                    @Price,
                    @IsExcluded,
                    GETDATE(),
                    GETDATE()
                );
            `);

        const data = apNormalizePricingRow(insertResult.recordset[0]);
        await logEmaAudit(
            pool,
            req,
            buildPricingAuditAction("create", null, data),
            "Device Pricing",
            "Success",
            { after: data },
            { entityType: "DevicePricing", entityID: String(data.PricingID || "") }
        );

        return res.json({
            success: true,
            message: "Device pricing added successfully.",
            data
        });
    } catch (err) {
        console.error("POST /api/settings/device-pricing/row error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to save device pricing row.",
            error: err.message
        });
    }
});

