// POST /api/settings/pc-aging-rule
// Body example:
// {
//   "enabled": true,
//   "ageSource": "RegDate",
//   "healthyMaxYears": 3,
//   "monitorMaxYears": 5,
//   "agingMinYears": 5,
//   "includeUnknownAge": false,
//   "replacementWindowMonths": 6,
//   "notes": ""
// }
app.post("/api/settings/pc-aging-rule", authenticateToken, async (req, res) => {
    try {
        const rule = normalizePcAgingRule(req.body || {});
        const settingValue = JSON.stringify(rule);

        const pool = await sql.connect(dbConfig);

        const existingResult = await pool.request()
            .input("SettingKey", sql.NVarChar(100), PC_AGING_RULE_KEY)
            .query(`
                SELECT TOP 1 SettingValue
                FROM AssetSettings WITH (NOLOCK)
                WHERE SettingKey = @SettingKey;
            `);
        const previousRule = safeParsePcAgingJson(existingResult.recordset?.[0]?.SettingValue);

        await pool.request()
            .input("SettingKey", sql.NVarChar(100), PC_AGING_RULE_KEY)
            .input("SettingValue", sql.NVarChar(sql.MAX), settingValue)
            .query(`
                IF EXISTS (
                    SELECT 1
                    FROM AssetSettings
                    WHERE SettingKey = @SettingKey
                )
                BEGIN
                    UPDATE AssetSettings
                    SET
                        SettingValue = @SettingValue,
                        UpdatedAt = GETDATE()
                    WHERE SettingKey = @SettingKey;
                END
                ELSE
                BEGIN
                    INSERT INTO AssetSettings
                    (
                        SettingKey,
                        SettingValue,
                        UpdatedAt
                    )
                    VALUES
                    (
                        @SettingKey,
                        @SettingValue,
                        GETDATE()
                    );
                END
            `);

        const agingAction = previousRule.enabled !== rule.enabled
            ? (rule.enabled ? "Enabled PC aging rule" : "Disabled PC aging rule")
            : "Updated PC aging rule";

        await logEmaAudit(
            pool,
            req,
            agingAction,
            "PC Aging Rule",
            "Success",
            {
                before: previousRule,
                after: rule,
                changes: buildAuditChangedFields(previousRule, rule)
            },
            { entityType: "PcAgingRule", entityID: PC_AGING_RULE_KEY }
        );

        return res.json({
            success: true,
            message: "PC aging rule saved successfully.",
            data: {
                settingKey: PC_AGING_RULE_KEY,
                rule
            }
        });
    } catch (err) {
        console.error("POST /api/settings/pc-aging-rule error:", err);

        return res.status(500).json({
            success: false,
            message: "Failed to save PC aging rule.",
            error: err.message
        });
    }
});

