// ============================================================
// IT OPERATIONS DASHBOARD API
// GET /api/dashboard/it-operations
// Live API only. No dummy/fallback dashboard data.
// ============================================================

function itopsToNumber(value, fallback = 0) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : fallback;
}

function itopsRound(value, digits = 1) {
    const factor = Math.pow(10, digits);
    return Math.round(itopsToNumber(value) * factor) / factor;
}

function itopsPercent(part, total, fallback = 0) {
    const denominator = itopsToNumber(total);
    if (!denominator) return Math.max(0, Math.min(100, fallback));
    const percent = itopsRound((itopsToNumber(part) / denominator) * 100, 1);
    return Math.max(0, Math.min(100, percent));
}

function itopsFormatInt(value) {
    return itopsToNumber(value).toLocaleString("en-US");
}

function itopsFormatPercent(value) {
    return `${itopsRound(value, 1).toFixed(1)}%`;
}

function itopsFormatDuration(minutes) {
    const totalMinutes = Math.max(0, Math.round(itopsToNumber(minutes)));
    if (!totalMinutes) return "0m";

    const hours = Math.floor(totalMinutes / 60);
    const mins = totalMinutes % 60;
    if (!hours) return `${mins}m`;
    if (!mins) return `${hours}h`;
    return `${hours}h ${mins}m`;
}

function itopsSeverity(value) {
    const text = String(value || "").trim();
    if (["Critical", "High", "Medium", "Low"].includes(text)) return text;
    return "Medium";
}

function itopsStatusTone(status, priority) {
    const normalizedStatus = String(status || "").toLowerCase();
    const normalizedPriority = String(priority || "").toLowerCase();

    if (normalizedStatus.includes("resolved") || normalizedStatus.includes("closed") || normalizedStatus.includes("transferred")) return "success";
    if (normalizedStatus.includes("running") || normalizedStatus.includes("progress") || normalizedStatus.includes("investigat")) return "info";
    if (normalizedStatus.includes("cancel") || normalizedStatus.includes("fail") || normalizedPriority === "critical") return "danger";
    if (normalizedPriority === "high" || normalizedPriority === "medium" || normalizedStatus.includes("await")) return "warning";
    return "neutral";
}

function itopsDateLabel(value) {
    if (!value) return "-";
    const date = value instanceof Date ? value : new Date(value);
    if (Number.isNaN(date.getTime())) return String(value);
    return date.toLocaleString("en-MY", {
        day: "2-digit",
        month: "short",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit"
    });
}

async function itopsTableExists(pool, tableName) {
    if (typeof tableExists === "function") {
        return tableExists(pool, tableName);
    }

    const result = await pool.request()
        .input("tableName", sql.NVarChar, tableName)
        .query(`
            SELECT 1 AS existsFlag
            FROM INFORMATION_SCHEMA.TABLES
            WHERE TABLE_NAME = @tableName
        `);

    return result.recordset.length > 0;
}

async function itopsColumnExists(pool, tableName, columnName) {
    const result = await pool.request()
        .input("tableName", sql.NVarChar, tableName)
        .input("columnName", sql.NVarChar, columnName)
        .query(`
            SELECT 1 AS existsFlag
            FROM INFORMATION_SCHEMA.COLUMNS
            WHERE TABLE_NAME = @tableName
              AND COLUMN_NAME = @columnName
        `);

    return result.recordset.length > 0;
}

function itopsRiskPercent(value, total) {
    return itopsPercent(value, total, 0);
}

function itopsRiskSeverityCount(count, criticalThreshold, highThreshold) {
    const value = itopsToNumber(count);
    if (value >= criticalThreshold) return "Critical";
    if (value >= highThreshold) return "High";
    if (value > 0) return "Medium";
    return "Low";
}

async function getItOpsHardwareSummary(pool) {
    const hasEmAssets = await itopsTableExists(pool, "TS_OBJECT_ROOT");
    const hasMdmAssets = await itopsTableExists(pool, "TSMDM_ASSET");
    const hasMdmMapping = await itopsTableExists(pool, "TSMDM_TS_OBJECT_MAPPING");

    if (!hasEmAssets && !hasMdmAssets) {
        return {
            totalDevices: 0,
            onlineDevices: 0,
            offlineDevices: 0,
            staleSync: 0,
            lockedDevices: 0,
            mdmDevices: 0,
            emDevices: 0,
            topModels: [],
            platformBreakdown: []
        };
    }

    const emSql = hasEmAssets
        ? `
            SELECT
                'EM' AS SourceType,
                ISNULL(NULLIF(ComputerName, ''), Object_DeviceID) AS DeviceName,
                ISNULL(Model, '-') AS Model,
                'Windows' AS Platform,
                CASE WHEN ConnectionStatus = 1 THEN 1 ELSE 0 END AS IsOnline,
                TRY_CONVERT(datetime, ConnectionTime) AS LastSeen
            FROM TS_OBJECT_ROOT WITH (NOLOCK)
            WHERE ISNULL(Object_Root_Idn, 0) > 0
        `
        : `
            SELECT 'EM' AS SourceType, NULL AS DeviceName, NULL AS Model, NULL AS Platform, 0 AS IsOnline, NULL AS LastSeen
            WHERE 1 = 0
        `;

    const mdmExcludeMappedSql = hasMdmMapping
        ? "AND a.MDM_Asset_Idn NOT IN (SELECT MDM_Asset_Idn FROM TSMDM_TS_OBJECT_MAPPING WITH (NOLOCK))"
        : "";

    const mdmSql = hasMdmAssets
        ? `
            SELECT
                'MDM' AS SourceType,
                ISNULL(NULLIF(a.DeviceName, ''), a.DeviceID) AS DeviceName,
                ISNULL(a.DeviceModelName, '-') AS Model,
                ISNULL(NULLIF(a.PlatformType, ''), 'MDM') AS Platform,
                CASE
                    WHEN TRY_CONVERT(int, a.ConnectionStatus) = 1 THEN 1
                    WHEN LOWER(CONVERT(nvarchar(50), a.ConnectionStatus)) = 'online' THEN 1
                    ELSE 0
                END AS IsOnline,
                TRY_CONVERT(datetime, COALESCE(a.DeviceTimeStamp, a.LastTimeStamp)) AS LastSeen
            FROM TSMDM_ASSET a WITH (NOLOCK)
            WHERE ISNULL(a.MDM_Asset_Idn, 0) > 0
            ${mdmExcludeMappedSql}
        `
        : `
            SELECT 'MDM' AS SourceType, NULL AS DeviceName, NULL AS Model, NULL AS Platform, 0 AS IsOnline, NULL AS LastSeen
            WHERE 1 = 0
        `;

    const summaryResult = await pool.request().query(`
        ;WITH Assets AS (
            ${emSql}
            UNION ALL
            ${mdmSql}
        )
        SELECT
            COUNT(1) AS TotalDevices,
            SUM(CASE WHEN IsOnline = 1 THEN 1 ELSE 0 END) AS OnlineDevices,
            SUM(CASE WHEN IsOnline = 0 THEN 1 ELSE 0 END) AS OfflineDevices,
            SUM(CASE WHEN LastSeen IS NULL OR LastSeen < DATEADD(day, -7, GETDATE()) THEN 1 ELSE 0 END) AS StaleSync,
            SUM(CASE WHEN SourceType = 'MDM' THEN 1 ELSE 0 END) AS MdmDevices,
            SUM(CASE WHEN SourceType = 'EM' THEN 1 ELSE 0 END) AS EmDevices
        FROM Assets;
    `);

    const platformResult = await pool.request().query(`
        ;WITH Assets AS (
            ${emSql}
            UNION ALL
            ${mdmSql}
        )
        SELECT TOP 6
            ISNULL(NULLIF(Platform, ''), 'Unknown') AS Name,
            COUNT(1) AS Value
        FROM Assets
        GROUP BY ISNULL(NULLIF(Platform, ''), 'Unknown')
        ORDER BY COUNT(1) DESC;
    `);

    const modelResult = await pool.request().query(`
        ;WITH Assets AS (
            ${emSql}
            UNION ALL
            ${mdmSql}
        )
        SELECT TOP 6
            ISNULL(NULLIF(Model, ''), 'Unknown Model') AS Name,
            COUNT(1) AS Value
        FROM Assets
        GROUP BY ISNULL(NULLIF(Model, ''), 'Unknown Model')
        ORDER BY COUNT(1) DESC;
    `);

    const summary = summaryResult.recordset?.[0] || {};
    const totalDevices = itopsToNumber(summary.TotalDevices);

    return {
        totalDevices,
        onlineDevices: itopsToNumber(summary.OnlineDevices),
        offlineDevices: itopsToNumber(summary.OfflineDevices),
        staleSync: itopsToNumber(summary.StaleSync),
        lockedDevices: 0,
        mdmDevices: itopsToNumber(summary.MdmDevices),
        emDevices: itopsToNumber(summary.EmDevices),
        platformBreakdown: (platformResult.recordset || []).map(row => ({
            name: row.Name || "Unknown",
            value: itopsToNumber(row.Value),
            percent: itopsPercent(row.Value, totalDevices)
        })),
        topModels: (modelResult.recordset || []).map(row => ({
            name: row.Name || "Unknown Model",
            value: itopsToNumber(row.Value),
            percent: itopsPercent(row.Value, totalDevices)
        }))
    };
}

async function getItOpsSoftwareSummary(pool) {
    const hasSoftware = await itopsTableExists(pool, "TSMDM_SW_LIST");
    const hasAsset = await itopsTableExists(pool, "TSMDM_ASSET");
    const hasCategory = await itopsTableExists(pool, "TS_SW_CATEGORY");

    if (!hasSoftware) {
        return {
            totalInstallations: 0,
            uniqueSoftware: 0,
            devicesWithSoftware: 0,
            unclassifiedSoftware: 0,
            latestScan: "-",
            topCategories: []
        };
    }

    const assetJoin = hasAsset
        ? "LEFT JOIN TSMDM_ASSET asset WITH (NOLOCK) ON sw.DeviceID = asset.DeviceID"
        : "";

    const categoryJoin = hasCategory
        ? "LEFT JOIN TS_SW_CATEGORY cat WITH (NOLOCK) ON sw.SW_CATEGORY = cat.CategoryID"
        : "";

    const categoryExpression = hasCategory
        ? "ISNULL(NULLIF(LTRIM(RTRIM(cat.CategoryName)), ''), 'Unclassified')"
        : "'Unclassified'";

    const result = await pool.request().query(`
        ;WITH SoftwareBase AS (
            SELECT
                CASE
                    WHEN TRY_CONVERT(uniqueidentifier, NULLIF(LTRIM(RTRIM(CAST(sw.Name AS NVARCHAR(255)))), '')) IS NOT NULL
                         AND NULLIF(LTRIM(RTRIM(CAST(sw.Id AS NVARCHAR(255)))), '') IS NOT NULL
                        THEN LTRIM(RTRIM(CAST(sw.Id AS NVARCHAR(255))))
                    WHEN NULLIF(LTRIM(RTRIM(CAST(sw.Name AS NVARCHAR(255)))), '') IS NOT NULL
                        THEN LTRIM(RTRIM(CAST(sw.Name AS NVARCHAR(255))))
                    WHEN NULLIF(LTRIM(RTRIM(CAST(sw.Id AS NVARCHAR(255)))), '') IS NOT NULL
                        THEN LTRIM(RTRIM(CAST(sw.Id AS NVARCHAR(255))))
                    ELSE '-'
                END AS SoftwareName,
                sw.DeviceID,
                ${categoryExpression} AS CategoryName,
                TRY_CONVERT(datetime, sw.SearchDate) AS SearchDate
            FROM TSMDM_SW_LIST sw WITH (NOLOCK)
            ${assetJoin}
            ${categoryJoin}
        )
        SELECT
            COUNT(1) AS TotalInstallations,
            COUNT(DISTINCT SoftwareName) AS UniqueSoftware,
            COUNT(DISTINCT DeviceID) AS DevicesWithSoftware,
            SUM(CASE WHEN CategoryName = 'Unclassified' THEN 1 ELSE 0 END) AS UnclassifiedSoftware,
            MAX(SearchDate) AS LatestScan
        FROM SoftwareBase;
    `);

    const categoryResult = await pool.request().query(`
        ;WITH SoftwareBase AS (
            SELECT
                ${categoryExpression} AS CategoryName
            FROM TSMDM_SW_LIST sw WITH (NOLOCK)
            ${assetJoin}
            ${categoryJoin}
        )
        SELECT TOP 6
            CategoryName AS Name,
            COUNT(1) AS Value
        FROM SoftwareBase
        GROUP BY CategoryName
        ORDER BY COUNT(1) DESC;
    `);

    const row = result.recordset?.[0] || {};
    const totalInstallations = itopsToNumber(row.TotalInstallations);

    return {
        totalInstallations,
        uniqueSoftware: itopsToNumber(row.UniqueSoftware),
        devicesWithSoftware: itopsToNumber(row.DevicesWithSoftware),
        unclassifiedSoftware: itopsToNumber(row.UnclassifiedSoftware),
        latestScan: itopsDateLabel(row.LatestScan),
        topCategories: (categoryResult.recordset || []).map(item => ({
            name: item.Name || "Unclassified",
            value: itopsToNumber(item.Value),
            percent: itopsPercent(item.Value, totalInstallations)
        }))
    };
}

async function getItOpsNetworkSummary(pool) {
    let rows = [];

    try {
        if (typeof getNetworkInventoryRows === "function") {
            rows = await getNetworkInventoryRows(pool, {});
        }
    } catch (err) {
        console.warn("ITOps V2 network summary getNetworkInventoryRows failed:", err.message || err);
    }

    let lastScan = "-";

    try {
        if (typeof getNetworkLastSearchDate === "function") {
            lastScan = getNetworkLastSearchDate ? await getNetworkLastSearchDate(pool) : "-";
        }
    } catch (err) {
        console.warn("ITOps V2 network last scan failed:", err.message || err);
    }

    const knownIps = rows.length;
    const registeredDevices = rows.filter(row => {
        const text = JSON.stringify(row || {}).toLowerCase();
        return text.includes("registered") || text.includes("installed") || text.includes("agent");
    }).length;
    const activeIps = rows.filter(row => {
        const text = JSON.stringify(row || {}).toLowerCase();
        return text.includes("active") || text.includes("online") || text.includes("up");
    }).length;

    const subnetSet = new Set();
    const workgroupMap = new Map();

    for (const row of rows) {
        const ip = row.IP || row.Ip || row.ip || row.IPAddress || row.IP_Address || row.Subnet || row.subnet || "";
        const subnet = String(ip).split(".").slice(0, 3).join(".");
        if (subnet) subnetSet.add(subnet);

        const workgroup = row.WorkGroup || row.Workgroup || row.WorkgroupName || row.GroupName || row.Object_Full_Name || "Unknown";
        workgroupMap.set(workgroup, (workgroupMap.get(workgroup) || 0) + 1);
    }

    const workgroups = [...workgroupMap.entries()]
        .sort((a, b) => b[1] - a[1])
        .slice(0, 6)
        .map(([name, value]) => ({
            name,
            value,
            percent: itopsPercent(value, knownIps)
        }));

    return {
        knownIps,
        registeredDevices,
        unregisteredIps: Math.max(knownIps - registeredDevices, 0),
        activeIps,
        subnetCount: subnetSet.size,
        lastScan: itopsDateLabel(lastScan),
        workgroups
    };
}

async function getItOpsGeoSummary(pool) {
    const hasGeo = await itopsTableExists(pool, "TSMDM_GEOLOCATION");

    if (!hasGeo) {
        return {
            trackedDevices: 0,
            staleLocations: 0,
            unknownLocations: 0,
            latestLocationTime: "-",
            topLocations: []
        };
    }

    const result = await pool.request().query(`
        SELECT
            COUNT(DISTINCT NULLIF(DeviceID, '')) AS TrackedDevices,
            COUNT(CASE WHEN TRY_CONVERT(datetime, [Time]) < DATEADD(day, -7, GETDATE()) OR [Time] IS NULL THEN 1 END) AS StaleLocations,
            COUNT(CASE WHEN LocationName IS NULL OR LocationName = '' OR LocationName = 'Unable to fetch the address.' THEN 1 END) AS UnknownLocations,
            MAX(TRY_CONVERT(datetime, [Time])) AS LatestLocationTime
        FROM TSMDM_GEOLOCATION WITH (NOLOCK);
    `);

    const locationResult = await pool.request().query(`
        SELECT TOP 6
            CASE
                WHEN LocationName IS NULL OR LocationName = '' OR LocationName = 'Unable to fetch the address.'
                    THEN 'Unknown Location'
                ELSE LocationName
            END AS Name,
            COUNT(1) AS Value
        FROM TSMDM_GEOLOCATION WITH (NOLOCK)
        GROUP BY CASE
            WHEN LocationName IS NULL OR LocationName = '' OR LocationName = 'Unable to fetch the address.'
                THEN 'Unknown Location'
            ELSE LocationName
        END
        ORDER BY COUNT(1) DESC;
    `);

    const row = result.recordset?.[0] || {};
    const total = itopsToNumber(row.TrackedDevices);

    return {
        trackedDevices: total,
        staleLocations: itopsToNumber(row.StaleLocations),
        unknownLocations: itopsToNumber(row.UnknownLocations),
        latestLocationTime: itopsDateLabel(row.LatestLocationTime),
        topLocations: (locationResult.recordset || []).map(item => ({
            name: item.Name || "Unknown Location",
            value: itopsToNumber(item.Value),
            percent: itopsPercent(item.Value, total)
        }))
    };
}

async function getItOpsTaskSummary(pool) {
    const hasJobs = await itopsTableExists(pool, "TS_JOB");

    if (!hasJobs) {
        return {
            totalTasks: 0,
            runningTasks: 0,
            completedTasks: 0,
            failedTasks: 0,
            latestTaskTime: "-",
            jobTypeBreakdown: [],
            recentTasks: []
        };
    }

    const result = await pool.request().query(`
        SELECT
            COUNT(1) AS TotalTasks,
            COUNT(CASE WHEN Job_Status IN (2200, 2201) THEN 1 END) AS RunningTasks,
            COUNT(CASE WHEN Job_Status = 2202 THEN 1 END) AS CompletedTasks,
            COUNT(CASE WHEN Job_Status IN (2203, 2204) THEN 1 END) AS FailedTasks,
            MAX(COALESCE(Job_StartTime, Job_ScheduleTime, Job_EndTime)) AS LatestTaskTime
        FROM TS_JOB WITH (NOLOCK);
    `);

    const typeResult = await pool.request().query(`
        SELECT TOP 6
            Job_Type AS JobType,
            COUNT(1) AS Value
        FROM TS_JOB WITH (NOLOCK)
        GROUP BY Job_Type
        ORDER BY COUNT(1) DESC;
    `);

    const recentResult = await pool.request().query(`
        SELECT TOP 5
            Job_Idn,
            Job_Type,
            Job_Status,
            ISNULL(NULLIF(Job_Description, ''), CONVERT(varchar(50), Job_Idn)) AS JobName,
            COALESCE(Job_StartTime, Job_ScheduleTime, Job_EndTime) AS TaskTime
        FROM TS_JOB WITH (NOLOCK)
        ORDER BY COALESCE(Job_StartTime, Job_ScheduleTime, Job_EndTime) DESC;
    `);

    const jobTypeLabels = typeof TASK_JOB_TYPE_LABELS !== "undefined" ? TASK_JOB_TYPE_LABELS : {};
    const statusLabels = typeof TASK_JOB_STATUS_LABELS !== "undefined" ? TASK_JOB_STATUS_LABELS : {};

    const summary = result.recordset?.[0] || {};
    const totalTasks = itopsToNumber(summary.TotalTasks);

    return {
        totalTasks,
        runningTasks: itopsToNumber(summary.RunningTasks),
        completedTasks: itopsToNumber(summary.CompletedTasks),
        failedTasks: itopsToNumber(summary.FailedTasks),
        latestTaskTime: itopsDateLabel(summary.LatestTaskTime),
        jobTypeBreakdown: (typeResult.recordset || []).map(row => {
            const value = itopsToNumber(row.Value);
            const typeLabel = jobTypeLabels[row.JobType] || `Job Type ${row.JobType || "-"}`;
            return {
                name: typeLabel,
                value,
                percent: itopsPercent(value, totalTasks)
            };
        }),
        recentTasks: (recentResult.recordset || []).map(row => {
            const status = statusLabels[row.Job_Status] || `Status ${row.Job_Status || "-"}`;
            return {
                id: String(row.Job_Idn || row.JobName),
                type: jobTypeLabels[row.Job_Type] || `Job Type ${row.Job_Type || "-"}`,
                status,
                target: row.JobName || "-",
                time: itopsDateLabel(row.TaskTime),
                tone: itopsStatusTone(status, "")
            };
        })
    };
}

async function getItOpsIncidentSummary(pool) {
    const hasIncidents = await itopsTableExists(pool, "HD_Incidents");

    if (!hasIncidents) {
        return {
            openIncidents: 0,
            overdueTickets: 0,
            mttrMinutes: 0,
            firstResponseMinutes: 0,
            slaAchievement: 0,
            priorityBreakdown: [
                { label: "Critical", value: 0, tone: "red" },
                { label: "High", value: 0, tone: "amber" },
                { label: "Medium", value: 0, tone: "yellow" },
                { label: "Low", value: 0, tone: "green" }
            ],
            incidentTrend: [],
            trendSummary: { newIncidents: 0, resolved: 0, openBacklog: 0 },
            activeAlerts: [],
            problematicSystems: []
        };
    }

    const summaryResult = await pool.request().query(`
        ;WITH Normalized AS (
            SELECT
                IncidentID,
                Title,
                ISNULL(Priority, 'Medium') AS Priority,
                ISNULL(Status, '') AS Status,
                ISNULL(AssetID, '') AS AssetID,
                ISNULL(AssignedTo, '') AS AssignedTo,
                ISNULL(AssignedLevel, '') AS AssignedLevel,
                TRY_CONVERT(datetime, CreatedAt) AS CreatedAtDate,
                TRY_CONVERT(datetime, FirstResponseAt) AS FirstResponseAtDate,
                TRY_CONVERT(datetime, ResolvedAt) AS ResolvedAtDate,
                TRY_CONVERT(datetime, SlaDue) AS SlaDueDate
            FROM HD_Incidents WITH (NOLOCK)
        )
        SELECT
            COUNT(CASE WHEN LOWER(Status) NOT IN ('resolved', 'closed') THEN 1 END) AS OpenIncidents,
            COUNT(CASE WHEN LOWER(Status) NOT IN ('resolved', 'closed') AND SlaDueDate IS NOT NULL AND SlaDueDate < GETDATE() THEN 1 END) AS OverdueTickets,
            AVG(CASE WHEN ResolvedAtDate IS NOT NULL AND CreatedAtDate IS NOT NULL THEN DATEDIFF(minute, CreatedAtDate, ResolvedAtDate) END) AS MttrMinutes,
            AVG(CASE WHEN FirstResponseAtDate IS NOT NULL AND CreatedAtDate IS NOT NULL THEN DATEDIFF(minute, CreatedAtDate, FirstResponseAtDate) END) AS FirstResponseMinutes,
            COUNT(CASE WHEN ResolvedAtDate IS NOT NULL AND SlaDueDate IS NOT NULL AND ResolvedAtDate <= SlaDueDate THEN 1 END) AS ResolvedWithinSla,
            COUNT(CASE WHEN ResolvedAtDate IS NOT NULL AND SlaDueDate IS NOT NULL THEN 1 END) AS ResolvedWithSla
        FROM Normalized;
    `);

    const priorityResult = await pool.request().query(`
        SELECT
            ISNULL(NULLIF(Priority, ''), 'Medium') AS Priority,
            COUNT(1) AS Total
        FROM HD_Incidents WITH (NOLOCK)
        WHERE LOWER(ISNULL(Status, '')) NOT IN ('resolved', 'closed')
        GROUP BY ISNULL(NULLIF(Priority, ''), 'Medium');
    `);

    const trendResult = await pool.request().query(`
        ;WITH Days AS (
            SELECT CAST(DATEADD(day, -6, CAST(GETDATE() AS date)) AS date) AS DayDate
            UNION ALL
            SELECT DATEADD(day, 1, DayDate)
            FROM Days
            WHERE DayDate < CAST(GETDATE() AS date)
        ), Normalized AS (
            SELECT
                TRY_CONVERT(datetime, CreatedAt) AS CreatedAtDate,
                TRY_CONVERT(datetime, ResolvedAt) AS ResolvedAtDate,
                ISNULL(Status, '') AS Status
            FROM HD_Incidents WITH (NOLOCK)
        )
        SELECT
            CONVERT(varchar(11), d.DayDate, 106) AS DayLabel,
            COUNT(CASE WHEN CAST(n.CreatedAtDate AS date) = d.DayDate THEN 1 END) AS NewIncidents,
            COUNT(CASE WHEN CAST(n.ResolvedAtDate AS date) = d.DayDate THEN 1 END) AS Resolved,
            COUNT(CASE
                WHEN n.CreatedAtDate IS NOT NULL
                 AND CAST(n.CreatedAtDate AS date) <= d.DayDate
                 AND (
                    LOWER(n.Status) NOT IN ('resolved', 'closed')
                    OR n.ResolvedAtDate IS NULL
                    OR CAST(n.ResolvedAtDate AS date) > d.DayDate
                 )
                THEN 1
            END) AS OpenBacklog
        FROM Days d
        LEFT JOIN Normalized n
            ON (
                CAST(n.CreatedAtDate AS date) <= d.DayDate
                OR CAST(n.ResolvedAtDate AS date) = d.DayDate
            )
        GROUP BY d.DayDate
        ORDER BY d.DayDate
        OPTION (MAXRECURSION 8);
    `);

    const alertsResult = await pool.request().query(`
        SELECT TOP 5
            ISNULL(Priority, 'Medium') AS Priority,
            ISNULL(Title, IncidentID) AS Title,
            ISNULL(AssetID, '-') AS AssetID,
            ISNULL(NULLIF(AssignedTo, ''), NULLIF(AssignedLevel, '')) AS Owner,
            ISNULL(Status, 'Open') AS Status
        FROM HD_Incidents WITH (NOLOCK)
        WHERE LOWER(ISNULL(Status, '')) NOT IN ('resolved', 'closed')
        ORDER BY
            CASE ISNULL(Priority, '')
                WHEN 'Critical' THEN 1
                WHEN 'High' THEN 2
                WHEN 'Medium' THEN 3
                ELSE 4
            END,
            TRY_CONVERT(datetime, CreatedAt) DESC;
    `);

    const problematicResult = await pool.request().query(`
        SELECT TOP 5
            ISNULL(NULLIF(AssetID, ''), 'Unassigned Asset') AS Device,
            COUNT(1) AS IncidentCount,
            SUM(CASE WHEN Priority = 'Critical' THEN 8 WHEN Priority = 'High' THEN 5 WHEN Priority = 'Medium' THEN 3 ELSE 1 END) AS RiskWeight,
            SUM(CASE WHEN LOWER(ISNULL(Status, '')) NOT IN ('resolved', 'closed') THEN 1 ELSE 0 END) AS OpenCount
        FROM HD_Incidents WITH (NOLOCK)
        WHERE AssetID IS NOT NULL AND AssetID <> ''
        GROUP BY ISNULL(NULLIF(AssetID, ''), 'Unassigned Asset')
        ORDER BY RiskWeight DESC, IncidentCount DESC;
    `);

    const summary = summaryResult.recordset?.[0] || {};
    const priorityMap = new Map((priorityResult.recordset || []).map(row => [String(row.Priority), itopsToNumber(row.Total)]));
    const incidentTrend = (trendResult.recordset || []).map(row => ({
        day: String(row.DayLabel || ""),
        newIncidents: itopsToNumber(row.NewIncidents),
        resolved: itopsToNumber(row.Resolved),
        open: itopsToNumber(row.OpenBacklog)
    }));

    const trendSummary = {
        newIncidents: incidentTrend.reduce((total, item) => total + item.newIncidents, 0),
        resolved: incidentTrend.reduce((total, item) => total + item.resolved, 0),
        openBacklog: incidentTrend.length ? incidentTrend[incidentTrend.length - 1].open : itopsToNumber(summary.OpenIncidents)
    };

    const resolvedWithSla = itopsToNumber(summary.ResolvedWithSla);
    const slaAchievement = resolvedWithSla
        ? itopsPercent(summary.ResolvedWithinSla, resolvedWithSla, 0)
        : 0;

    return {
        openIncidents: itopsToNumber(summary.OpenIncidents),
        overdueTickets: itopsToNumber(summary.OverdueTickets),
        mttrMinutes: itopsToNumber(summary.MttrMinutes),
        firstResponseMinutes: itopsToNumber(summary.FirstResponseMinutes),
        slaAchievement,
        priorityBreakdown: [
            { label: "Critical", value: priorityMap.get("Critical") || 0, tone: "red" },
            { label: "High", value: priorityMap.get("High") || 0, tone: "amber" },
            { label: "Medium", value: priorityMap.get("Medium") || 0, tone: "yellow" },
            { label: "Low", value: priorityMap.get("Low") || 0, tone: "green" }
        ],
        incidentTrend,
        trendSummary,
        activeAlerts: (alertsResult.recordset || []).map(row => ({
            severity: itopsSeverity(row.Priority),
            alert: row.Title || "Incident requires attention",
            system: row.AssetID || "-",
            owner: row.Owner || "Unassigned",
            status: row.Status || "Open",
            tone: itopsStatusTone(row.Status, row.Priority)
        })),
        problematicSystems: (problematicResult.recordset || []).map((row, index) => {
            const score = Math.min(99, Math.max(10, itopsToNumber(row.RiskWeight) * 8 + itopsToNumber(row.OpenCount) * 4));
            return {
                rank: index + 1,
                device: row.Device || "-",
                score,
                trend: [Math.max(0, score - 18), Math.max(0, score - 12), Math.max(0, score - 20), Math.max(0, score - 8), Math.max(0, score - 6), Math.max(0, score - 10), score]
            };
        })
    };
}

async function getItOpsPatchSummary(pool) {
    const hasPatchStatus = await itopsTableExists(pool, "TS_UPDATE_ONLINE_STATUS");
    const hasPatchMaster = await itopsTableExists(pool, "TS_UPDATE_ONLINE_MASTER");
    const hasRelations = await itopsTableExists(pool, "TS_OBJECT_RELATION");

    if (!hasPatchStatus) {
        return {
            patchCompliance: 0,
            missingPatches: 0,
            criticalVulnerabilities: 0,
            patchDepartments: []
        };
    }

    const summaryResult = await pool.request().query(`
        SELECT
            COUNT(CASE WHEN ISNULL(IsApplicable, 0) = 1 THEN 1 END) AS ApplicablePatches,
            COUNT(CASE WHEN ISNULL(IsApplicable, 0) = 1 AND (ISNULL(IsInstalled, 0) = 1 OR ISNULL(IsDownloaded, 0) = 1) THEN 1 END) AS InstalledPatches,
            COUNT(CASE WHEN ISNULL(IsApplicable, 0) = 1 AND ISNULL(IsInstalled, 0) = 0 AND ISNULL(IsDownloaded, 0) = 0 THEN 1 END) AS MissingPatches
        FROM TS_UPDATE_ONLINE_STATUS WITH (NOLOCK);
    `);

    let criticalVulnerabilities = 0;

    if (hasPatchMaster) {
        const criticalResult = await pool.request().query(`
            SELECT COUNT(1) AS CriticalMissing
            FROM TS_UPDATE_ONLINE_STATUS s WITH (NOLOCK)
            LEFT JOIN TS_UPDATE_ONLINE_MASTER m WITH (NOLOCK)
                ON m.UpdateID = s.UpdateID
               AND m.RevisionNumber = s.RevisionNumber
            WHERE ISNULL(s.IsApplicable, 0) = 1
              AND ISNULL(s.IsInstalled, 0) = 0
              AND ISNULL(s.IsDownloaded, 0) = 0
              AND LOWER(ISNULL(m.MsrcSeverity, '')) = 'critical';
        `);

        criticalVulnerabilities = itopsToNumber(criticalResult.recordset?.[0]?.CriticalMissing);
    }

    let patchDepartments = [];

    if (hasRelations) {
        const departmentResult = await pool.request().query(`
            SELECT TOP 7
                ISNULL(rel.Object_Rel_Name, ISNULL(rel.Object_Full_Name, 'Unassigned')) AS Department,
                COUNT(CASE WHEN ISNULL(s.IsApplicable, 0) = 1 THEN 1 END) AS ApplicablePatches,
                COUNT(CASE WHEN ISNULL(s.IsApplicable, 0) = 1 AND (ISNULL(s.IsInstalled, 0) = 1 OR ISNULL(s.IsDownloaded, 0) = 1) THEN 1 END) AS InstalledPatches
            FROM TS_UPDATE_ONLINE_STATUS s WITH (NOLOCK)
            LEFT JOIN TS_OBJECT_ROOT r WITH (NOLOCK)
                ON s.Object_Root_Idn = r.Object_Root_Idn
            LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK)
                ON r.Object_Rel_Idn = rel.Object_Rel_Idn
            GROUP BY ISNULL(rel.Object_Rel_Name, ISNULL(rel.Object_Full_Name, 'Unassigned'))
            ORDER BY COUNT(CASE WHEN ISNULL(s.IsApplicable, 0) = 1 THEN 1 END) DESC;
        `);

        patchDepartments = (departmentResult.recordset || []).map(row => ({
            name: row.Department || "Unassigned",
            percent: itopsPercent(row.InstalledPatches, row.ApplicablePatches, 0)
        }));
    }

    const summary = summaryResult.recordset?.[0] || {};

    return {
        patchCompliance: itopsPercent(summary.InstalledPatches, summary.ApplicablePatches, 0),
        missingPatches: itopsToNumber(summary.MissingPatches),
        criticalVulnerabilities,
        patchDepartments
    };
}

async function getItOpsDepartmentRows(pool) {
    const hasRelations = await itopsTableExists(pool, "TS_OBJECT_RELATION");
    const hasEmAssets = await itopsTableExists(pool, "TS_OBJECT_ROOT");
    const hasIncidents = await itopsTableExists(pool, "HD_Incidents");
    const hasPatchStatus = await itopsTableExists(pool, "TS_UPDATE_ONLINE_STATUS");

    if (!hasRelations || !hasEmAssets) return [];

    const incidentJoinSql = hasIncidents
        ? `
            LEFT JOIN (
                SELECT
                    CustomerName,
                    COUNT(CASE WHEN LOWER(ISNULL(Status, '')) NOT IN ('resolved', 'closed') THEN 1 END) AS OpenIncidents
                FROM HD_Incidents WITH (NOLOCK)
                GROUP BY CustomerName
            ) inc
                ON inc.CustomerName = rel.Object_Full_Name
                OR inc.CustomerName = rel.Object_Rel_Name
        `
        : "";

    const patchJoinSql = hasPatchStatus
        ? `
            LEFT JOIN (
                SELECT
                    Object_Root_Idn,
                    COUNT(CASE WHEN ISNULL(IsApplicable, 0) = 1 THEN 1 END) AS ApplicablePatches,
                    COUNT(CASE WHEN ISNULL(IsApplicable, 0) = 1 AND (ISNULL(IsInstalled, 0) = 1 OR ISNULL(IsDownloaded, 0) = 1) THEN 1 END) AS InstalledPatches
                FROM TS_UPDATE_ONLINE_STATUS WITH (NOLOCK)
                GROUP BY Object_Root_Idn
            ) patch
                ON patch.Object_Root_Idn = root.Object_Root_Idn
        `
        : "";

    const result = await pool.request().query(`
        SELECT TOP 8
            ISNULL(rel.Object_Rel_Name, ISNULL(rel.Object_Full_Name, 'Unassigned')) AS Department,
            COUNT(DISTINCT root.Object_Root_Idn) AS Assets,
            SUM(CASE WHEN root.ConnectionStatus = 1 THEN 1 ELSE 0 END) AS OnlineAssets,
            SUM(ISNULL(patch.ApplicablePatches, 0)) AS ApplicablePatches,
            SUM(ISNULL(patch.InstalledPatches, 0)) AS InstalledPatches,
            MAX(ISNULL(inc.OpenIncidents, 0)) AS OpenIncidents
        FROM TS_OBJECT_ROOT root WITH (NOLOCK)
        LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK)
            ON root.Object_Rel_Idn = rel.Object_Rel_Idn
        ${patchJoinSql}
        ${incidentJoinSql}
        GROUP BY ISNULL(rel.Object_Rel_Name, ISNULL(rel.Object_Full_Name, 'Unassigned'))
        ORDER BY COUNT(DISTINCT root.Object_Root_Idn) DESC;
    `);

    return (result.recordset || []).map(row => {
        const patchCompliance = itopsPercent(row.InstalledPatches, row.ApplicablePatches, 0);
        const onlineHealth = itopsPercent(row.OnlineAssets, row.Assets, 0);
        const healthScore = itopsRound((patchCompliance * 0.55) + (onlineHealth * 0.45), 0);

        return {
            department: row.Department || "Unassigned",
            assets: itopsToNumber(row.Assets),
            patchCompliance,
            openIncidents: itopsToNumber(row.OpenIncidents),
            healthScore
        };
    });
}

async function getItOpsRiskSummary(pool, { hardware, patchSummary, network, geolocation, tasks }) {
    const totalDevices = itopsToNumber(hardware.totalDevices);
    const defaultAgeLimit = 7;

    let oldBiosDevices = 0;
    let unsupportedOsDevices = 0;
    let outdatedOsDevices = 0;
    let missingHardwareIdentity = 0;
    let topHardwareRisk = [];
    let osBreakdown = [];
    let biosAgeBreakdown = [];

    const hasAssets = await itopsTableExists(pool, "Assets");
    const hasOsSupport = await itopsTableExists(pool, "OSSupportCache");
    const hasAssetSettings = await itopsTableExists(pool, "AssetSettings");

    let effectiveAgeLimit = defaultAgeLimit;
    if (hasAssetSettings) {
        try {
            const settingsRes = await pool.request().query("SELECT TOP 1 SettingValue FROM AssetSettings WITH (NOLOCK) WHERE SettingKey = 'PCAgeLimit'");
            effectiveAgeLimit = parseInt(settingsRes.recordset?.[0]?.SettingValue, 10) || defaultAgeLimit;
        } catch (err) {
            console.warn("ITOps risk AssetSettings lookup failed:", err.message || err);
        }
    }

    if (hasAssets) {
        const supportJoin = hasOsSupport
            ? `
                LEFT JOIN OSSupportCache osc WITH (NOLOCK)
                  ON osc.OSKey = CASE
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 7%' THEN '7-sp1'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 8.1%' THEN '8.1'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 8%' THEN '8'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows xp%' THEN '5-sp3'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%vista%' THEN '6-sp2'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 11%24h2%' THEN '11-24h2-w'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 11%23h2%' THEN '11-23h2-w'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 11%22h2%' THEN '11-22h2-w'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 11%' THEN '11-24h2-w'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%22h2%' THEN '10-22h2'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%21h2%' THEN '10-21h2-w'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%21h1%' THEN '10-21h1'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%20h2%' THEN '10-20h2-w'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%' THEN '10-22h2'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%server 2025%' THEN 'server-2025'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%server 2022%' THEN 'server-2022'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%server 2019%' THEN 'server-2019'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%server 2016%' THEN 'server-2016'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%server 2012 r2%' THEN 'server-2012-r2'
                    WHEN LOWER(ISNULL(a.OS, '')) LIKE '%server 2012%' THEN 'server-2012'
                    ELSE NULL
                  END
            `
            : "";

        const riskCte = `
            ;WITH AssetRisk AS (
                SELECT
                    a.AssetID,
                    ISNULL(NULLIF(a.ComputerName, ''), ISNULL(NULLIF(a.AssetTag, ''), a.AssetID)) AS DeviceName,
                    ISNULL(NULLIF(a.CustomerName, ''), ISNULL(NULLIF(a.Department, ''), 'Unmapped')) AS Department,
                    ISNULL(NULLIF(a.Model, ''), '-') AS Model,
                    ISNULL(NULLIF(a.OS, ''), 'Unknown') AS OSName,
                    ISNULL(NULLIF(a.BiosDate, ''), '-') AS BiosDate,
                    TRY_CONVERT(int, a.PCAge) AS PCAge,
                    a.ConnectionTime,
                    ISNULL(NULLIF(a.AgentStatus, ''), '-') AS AgentStatus,
                    CASE
                        WHEN ${hasOsSupport ? "ISNULL(osc.IsEol, 0) = 1 OR " : ""}
                             LOWER(ISNULL(a.OS, '')) LIKE '%windows 7%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%windows 8%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%windows xp%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%vista%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%server 2003%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%server 2008%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%server 2012%'
                        THEN 1 ELSE 0
                    END AS IsUnsupportedOs,
                    CASE
                        WHEN ${hasOsSupport ? "osc.EolDate IS NOT NULL AND TRY_CONVERT(date, osc.EolDate) > GETDATE() AND DATEDIFF(month, GETDATE(), TRY_CONVERT(date, osc.EolDate)) <= 24 OR " : ""}
                             LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%20h2%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%21h1%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%windows 10%21h2%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%windows 11%21h2%'
                          OR LOWER(ISNULL(a.OS, '')) LIKE '%windows 11%22h2%'
                        THEN 1 ELSE 0
                    END AS IsOutdatedOs,
                    CASE
                        WHEN TRY_CONVERT(int, a.PCAge) >= @PCAgeLimit
                          OR (TRY_CONVERT(date, a.BiosDate) IS NOT NULL AND TRY_CONVERT(date, a.BiosDate) < DATEADD(year, -@PCAgeLimit, GETDATE()))
                        THEN 1 ELSE 0
                    END AS IsOldBios,
                    CASE
                        WHEN NULLIF(LTRIM(RTRIM(ISNULL(a.Model, ''))), '') IS NULL
                          OR NULLIF(LTRIM(RTRIM(ISNULL(a.ComputerName, ''))), '') IS NULL
                          OR NULLIF(LTRIM(RTRIM(ISNULL(a.IP, ''))), '') IS NULL
                        THEN 1 ELSE 0
                    END AS HasMissingIdentity,
                    CASE WHEN a.ConnectionTime IS NULL OR a.ConnectionTime < DATEADD(day, -7, GETDATE()) THEN 1 ELSE 0 END AS IsStale
                FROM Assets a WITH (NOLOCK)
                ${supportJoin}
            )
        `;

        const summaryResult = await pool.request()
            .input("PCAgeLimit", sql.Int, effectiveAgeLimit)
            .query(`${riskCte}
                SELECT
                    COUNT(1) AS TotalAssets,
                    SUM(IsOldBios) AS OldBiosDevices,
                    SUM(IsUnsupportedOs) AS UnsupportedOsDevices,
                    SUM(IsOutdatedOs) AS OutdatedOsDevices,
                    SUM(HasMissingIdentity) AS MissingHardwareIdentity,
                    SUM(IsStale) AS StaleHardwareDevices
                FROM AssetRisk;
            `);

        const summary = summaryResult.recordset?.[0] || {};
        const totalAssetRows = itopsToNumber(summary.TotalAssets) || totalDevices || 1;
        oldBiosDevices = itopsToNumber(summary.OldBiosDevices);
        unsupportedOsDevices = itopsToNumber(summary.UnsupportedOsDevices);
        outdatedOsDevices = itopsToNumber(summary.OutdatedOsDevices);
        missingHardwareIdentity = itopsToNumber(summary.MissingHardwareIdentity);

        const osResult = await pool.request()
            .input("PCAgeLimit", sql.Int, effectiveAgeLimit)
            .query(`${riskCte}
                SELECT
                    CASE
                        WHEN IsUnsupportedOs = 1 THEN 'Critical / Unsupported'
                        WHEN IsOutdatedOs = 1 THEN 'Watch / Outdated'
                        WHEN OSName = 'Unknown' THEN 'Unknown OS'
                        ELSE 'Supported Windows'
                    END AS Name,
                    COUNT(1) AS Value
                FROM AssetRisk
                GROUP BY CASE
                    WHEN IsUnsupportedOs = 1 THEN 'Critical / Unsupported'
                    WHEN IsOutdatedOs = 1 THEN 'Watch / Outdated'
                    WHEN OSName = 'Unknown' THEN 'Unknown OS'
                    ELSE 'Supported Windows'
                END
                ORDER BY COUNT(1) DESC;
            `);

        const biosResult = await pool.request()
            .input("PCAgeLimit", sql.Int, effectiveAgeLimit)
            .query(`
                SELECT
                    CASE
                        WHEN TRY_CONVERT(int, PCAge) >= @PCAgeLimit
                          OR (TRY_CONVERT(date, BiosDate) IS NOT NULL AND TRY_CONVERT(date, BiosDate) < DATEADD(year, -@PCAgeLimit, GETDATE()))
                        THEN 'Old BIOS / lifecycle risk'
                        WHEN TRY_CONVERT(int, PCAge) BETWEEN 4 AND @PCAgeLimit - 1
                        THEN 'Watch BIOS age'
                        WHEN TRY_CONVERT(int, PCAge) IS NULL AND TRY_CONVERT(date, BiosDate) IS NULL
                        THEN 'Missing BIOS date'
                        ELSE 'BIOS age OK'
                    END AS Name,
                    COUNT(1) AS Value
                FROM Assets WITH (NOLOCK)
                GROUP BY CASE
                    WHEN TRY_CONVERT(int, PCAge) >= @PCAgeLimit
                      OR (TRY_CONVERT(date, BiosDate) IS NOT NULL AND TRY_CONVERT(date, BiosDate) < DATEADD(year, -@PCAgeLimit, GETDATE()))
                    THEN 'Old BIOS / lifecycle risk'
                    WHEN TRY_CONVERT(int, PCAge) BETWEEN 4 AND @PCAgeLimit - 1
                    THEN 'Watch BIOS age'
                    WHEN TRY_CONVERT(int, PCAge) IS NULL AND TRY_CONVERT(date, BiosDate) IS NULL
                    THEN 'Missing BIOS date'
                    ELSE 'BIOS age OK'
                END
                ORDER BY COUNT(1) DESC;
            `);

        const topResult = await pool.request()
            .input("PCAgeLimit", sql.Int, effectiveAgeLimit)
            .query(`${riskCte}
                SELECT TOP 25
                    DeviceName,
                    OSName,
                    Model,
                    Department,
                    BiosDate,
                    ConnectionTime AS LastSeen,
                    (
                        CASE WHEN IsUnsupportedOs = 1 THEN 45 ELSE 0 END
                        + CASE WHEN IsOldBios = 1 THEN 30 ELSE 0 END
                        + CASE WHEN IsStale = 1 THEN 18 ELSE 0 END
                        + CASE WHEN HasMissingIdentity = 1 THEN 12 ELSE 0 END
                    ) AS RiskScore,
                    CONCAT(
                        CASE WHEN IsUnsupportedOs = 1 THEN 'Unsupported OS; ' ELSE '' END,
                        CASE WHEN IsOldBios = 1 THEN 'Old BIOS; ' ELSE '' END,
                        CASE WHEN IsStale = 1 THEN 'Stale connection; ' ELSE '' END,
                        CASE WHEN HasMissingIdentity = 1 THEN 'Missing identity; ' ELSE '' END
                    ) AS Reasons
                FROM AssetRisk
                WHERE IsUnsupportedOs = 1 OR IsOldBios = 1 OR IsStale = 1 OR HasMissingIdentity = 1
                ORDER BY RiskScore DESC, DeviceName ASC;
            `);

        osBreakdown = (osResult.recordset || []).map(row => ({
            name: row.Name,
            value: itopsToNumber(row.Value),
            percent: itopsRiskPercent(row.Value, totalAssetRows),
            tone: row.Name.includes("Critical") ? "critical" : row.Name.includes("Watch") ? "warning" : row.Name.includes("Supported") ? "good" : "neutral"
        }));

        biosAgeBreakdown = (biosResult.recordset || []).map(row => ({
            name: row.Name,
            value: itopsToNumber(row.Value),
            percent: itopsRiskPercent(row.Value, totalAssetRows),
            tone: row.Name.includes("Old") ? "critical" : row.Name.includes("Watch") ? "warning" : row.Name.includes("OK") ? "good" : "neutral"
        }));

        topHardwareRisk = (topResult.recordset || []).map(row => ({
            deviceName: row.DeviceName || "-",
            platform: "Windows",
            model: row.Model || "-",
            department: row.Department || "Unmapped",
            lastSeen: itopsDateLabel(row.LastSeen),
            biosDate: row.BiosDate || "-",
            osName: row.OSName || "-",
            riskScore: itopsToNumber(row.RiskScore),
            reasons: String(row.Reasons || "").replace(/;\\s*$/, "")
        }));
    } else if (await itopsTableExists(pool, "TS_OBJECT_ROOT")) {
        const hasTshiCurrent = await itopsTableExists(pool, "TSHI_OBJECT_CURRENT");
        const hasTshiValue = await itopsTableExists(pool, "TSHI_OBJECT_VALUE");
        const hasClientInfo = await itopsTableExists(pool, "TS_CLIENT_INFO");
        const hasOs = await itopsColumnExists(pool, "TS_OBJECT_ROOT", "OS");
        const hasOsLower = await itopsColumnExists(pool, "TS_OBJECT_ROOT", "os");
        const hasOsVersion = await itopsColumnExists(pool, "TS_OBJECT_ROOT", "OS_Version");
        const hasOsVersionLower = await itopsColumnExists(pool, "TS_OBJECT_ROOT", "os_version");

        const osExpr = hasOs ? "r.OS" : hasOsLower ? "r.os" : hasClientInfo ? "ci.OS_FullName" : "'Windows'";
        const osVersionExpr = hasOsVersion ? "r.OS_Version" : hasOsVersionLower ? "r.os_version" : "NULL";
        const biosJoin = hasTshiCurrent && hasTshiValue
            ? "LEFT JOIN TSHI_OBJECT_CURRENT cur WITH (NOLOCK) ON r.Object_Root_Idn = cur.Object_Root_Idn AND cur.Object_Field_Idn = 14 LEFT JOIN TSHI_OBJECT_VALUE val WITH (NOLOCK) ON val.Object_Value_Idn = cur.Object_Value_Idn"
            : "";
        const clientJoin = hasClientInfo
            ? "LEFT JOIN TS_CLIENT_INFO ci WITH (NOLOCK) ON r.Object_Root_Idn = ci.Object_Root_Idn"
            : "";
        const biosExpr = hasTshiCurrent && hasTshiValue ? "val.Object_Value_Str" : "NULL";
        const serialExpr = hasClientInfo ? "ci.BiosSerialkey" : "NULL";

        const rootResult = await pool.request()
            .input("PCAgeLimit", sql.Int, effectiveAgeLimit)
            .query(`
                ;WITH RootRisk AS (
                    SELECT
                        ISNULL(NULLIF(r.ComputerName, ''), r.Object_DeviceID) AS DeviceName,
                        ISNULL(rel.Object_Full_Name, 'Unmapped') AS Department,
                        ISNULL(NULLIF(r.Model, ''), '-') AS Model,
                        ISNULL(NULLIF(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), ''), 'Windows') AS OSName,
                        ISNULL(NULLIF(${biosExpr}, ''), '-') AS BiosDate,
                        r.ConnectionTime AS LastSeen,
                        CASE WHEN r.ConnectionTime IS NULL OR r.ConnectionTime < DATEADD(day, -7, GETDATE()) THEN 1 ELSE 0 END AS IsStale,
                        CASE WHEN NULLIF(LTRIM(RTRIM(ISNULL(r.Model, ''))), '') IS NULL OR NULLIF(LTRIM(RTRIM(ISNULL(r.IP, ''))), '') IS NULL OR NULLIF(LTRIM(RTRIM(ISNULL(${serialExpr}, ''))), '') IS NULL THEN 1 ELSE 0 END AS HasMissingIdentity,
                        CASE WHEN TRY_CONVERT(date, ${biosExpr}) IS NOT NULL AND TRY_CONVERT(date, ${biosExpr}) < DATEADD(year, -@PCAgeLimit, GETDATE()) THEN 1 ELSE 0 END AS IsOldBios,
                        CASE
                            WHEN LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%windows 7%'
                              OR LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%windows 8%'
                              OR LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%windows xp%'
                              OR LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%server 2012%'
                            THEN 1 ELSE 0
                        END AS IsUnsupportedOs,
                        CASE
                            WHEN LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%20h2%'
                              OR LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%21h1%'
                              OR LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%21h2%'
                              OR LOWER(ISNULL(CONCAT(${osExpr}, ' ', ISNULL(${osVersionExpr}, '')), '')) LIKE '%22h2%'
                            THEN 1 ELSE 0
                        END AS IsOutdatedOs
                    FROM TS_OBJECT_ROOT r WITH (NOLOCK)
                    LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK) ON r.Object_Rel_Idn = rel.Object_Rel_Idn
                    ${biosJoin}
                    ${clientJoin}
                )
                SELECT
                    COUNT(1) AS TotalAssets,
                    SUM(IsOldBios) AS OldBiosDevices,
                    SUM(IsUnsupportedOs) AS UnsupportedOsDevices,
                    SUM(IsOutdatedOs) AS OutdatedOsDevices,
                    SUM(HasMissingIdentity) AS MissingHardwareIdentity,
                    SUM(IsStale) AS StaleHardwareDevices
                FROM RootRisk;
            `);

        const summary = rootResult.recordset?.[0] || {};
        const totalRootRows = itopsToNumber(summary.TotalAssets) || totalDevices || 1;
        oldBiosDevices = itopsToNumber(summary.OldBiosDevices);
        unsupportedOsDevices = itopsToNumber(summary.UnsupportedOsDevices);
        outdatedOsDevices = itopsToNumber(summary.OutdatedOsDevices);
        missingHardwareIdentity = itopsToNumber(summary.MissingHardwareIdentity);

        osBreakdown = [
            { name: "Critical / Unsupported", value: unsupportedOsDevices, percent: itopsRiskPercent(unsupportedOsDevices, totalRootRows), tone: "critical" },
            { name: "Watch / Outdated", value: outdatedOsDevices, percent: itopsRiskPercent(outdatedOsDevices, totalRootRows), tone: "warning" },
            { name: "Supported / Unknown Windows", value: Math.max(totalRootRows - unsupportedOsDevices - outdatedOsDevices, 0), percent: itopsRiskPercent(Math.max(totalRootRows - unsupportedOsDevices - outdatedOsDevices, 0), totalRootRows), tone: "good" }
        ];

        biosAgeBreakdown = [
            { name: "Old BIOS / lifecycle risk", value: oldBiosDevices, percent: itopsRiskPercent(oldBiosDevices, totalRootRows), tone: "critical" },
            { name: "Missing identity / BIOS", value: missingHardwareIdentity, percent: itopsRiskPercent(missingHardwareIdentity, totalRootRows), tone: "warning" },
            { name: "BIOS age OK / not flagged", value: Math.max(totalRootRows - oldBiosDevices - missingHardwareIdentity, 0), percent: itopsRiskPercent(Math.max(totalRootRows - oldBiosDevices - missingHardwareIdentity, 0), totalRootRows), tone: "good" }
        ];

        topHardwareRisk = [];
    }

    const staleHardwareDevices = itopsToNumber(hardware.staleSync);
    const missingGeoDevices = Math.max(totalDevices - itopsToNumber(geolocation.trackedDevices), 0);
    const staleGeoDevices = itopsToNumber(geolocation.staleLocations);
    const unknownGeoDevices = itopsToNumber(geolocation.unknownLocations);
    const patchCriticalItems = itopsToNumber(patchSummary.criticalVulnerabilities);
    const failedTaskItems = itopsToNumber(tasks.failedTasks);
    const networkRiskItems = itopsToNumber(network.unregisteredIps);
    const geolocationRiskItems = missingGeoDevices + staleGeoDevices + unknownGeoDevices;
    const hardwareRiskItems = oldBiosDevices + unsupportedOsDevices + outdatedOsDevices + staleHardwareDevices + missingHardwareIdentity;

    const totalCritical = patchCriticalItems + unsupportedOsDevices + Math.floor(oldBiosDevices * 0.5) + Math.floor(failedTaskItems * 0.25);
    const totalHigh = staleHardwareDevices + oldBiosDevices + failedTaskItems + Math.floor(geolocationRiskItems * 0.35) + Math.floor(networkRiskItems * 0.25);
    const totalMedium = outdatedOsDevices + missingHardwareIdentity + Math.floor(geolocationRiskItems * 0.65) + Math.floor(networkRiskItems * 0.75);
    const totalRiskItems = hardwareRiskItems + geolocationRiskItems + patchCriticalItems + failedTaskItems + networkRiskItems;
    const score = Math.max(0, Math.min(100, Math.round((totalCritical * 3 + totalHigh * 1.5 + totalMedium) / Math.max(totalDevices || totalRiskItems || 1, 1) * 100)));

    const severityTotal = Math.max(totalCritical + totalHigh + totalMedium, 1);
    const categoryTotal = Math.max(totalRiskItems, 1);

    const topFindings = [
        { id: "risk-unsupported-os", module: "Hardware / Windows", title: "Unsupported or legacy Windows devices", count: unsupportedOsDevices, severity: itopsRiskSeverityCount(unsupportedOsDevices, 1, 10), recommendation: "Review OS support baseline and plan upgrade or isolation." },
        { id: "risk-old-bios", module: "Hardware / BIOS", title: "Old BIOS or lifecycle risk devices", count: oldBiosDevices, severity: itopsRiskSeverityCount(oldBiosDevices, 10, 25), recommendation: "Schedule BIOS update or hardware refresh by model." },
        { id: "risk-location-coverage", module: "Geolocation", title: "Location coverage and freshness risk", count: geolocationRiskItems, severity: itopsRiskSeverityCount(geolocationRiskItems, 50, 250), recommendation: "Refresh MDM location collection and check devices with missing coordinates." },
        { id: "risk-patch-critical", module: "Patch", title: "Critical missing patch exposure", count: patchCriticalItems, severity: patchCriticalItems > 0 ? "Critical" : "Low", recommendation: "Prioritize critical patch deployment before normal updates." },
        { id: "risk-failed-tasks", module: "Task List", title: "Stopped or cancelled automation jobs", count: failedTaskItems, severity: itopsRiskSeverityCount(failedTaskItems, 50, 150), recommendation: "Review failed jobs and rerun inventory or remote tasks." },
        { id: "risk-network-registration", module: "Network", title: "Unregistered network IP records", count: networkRiskItems, severity: itopsRiskSeverityCount(networkRiskItems, 100, 250), recommendation: "Validate unmanaged or unmapped IP records against hardware inventory." }
    ].filter(item => item.count > 0).sort((a, b) => b.count - a.count);

    return {
        score,
        totalRiskItems,
        totalCritical,
        totalHigh,
        totalMedium,
        hardwareRiskItems,
        oldBiosDevices,
        unsupportedOsDevices,
        outdatedOsDevices,
        staleHardwareDevices,
        missingHardwareIdentity,
        geolocationRiskItems,
        missingGeoDevices,
        staleGeoDevices,
        unknownGeoDevices,
        patchCriticalItems,
        failedTaskItems,
        networkRiskItems,
        severityBreakdown: [
            { name: "Critical", value: totalCritical, percent: itopsRiskPercent(totalCritical, severityTotal), tone: "critical" },
            { name: "High", value: totalHigh, percent: itopsRiskPercent(totalHigh, severityTotal), tone: "warning" },
            { name: "Medium", value: totalMedium, percent: itopsRiskPercent(totalMedium, severityTotal), tone: "neutral" }
        ],
        categoryBreakdown: [
            { name: "Hardware / Windows / BIOS", value: hardwareRiskItems, percent: itopsRiskPercent(hardwareRiskItems, categoryTotal), tone: hardwareRiskItems ? "critical" : "good" },
            { name: "Location Coverage / Geolocation", value: geolocationRiskItems, percent: itopsRiskPercent(geolocationRiskItems, categoryTotal), tone: geolocationRiskItems ? "warning" : "good" },
            { name: "Critical Patch", value: patchCriticalItems, percent: itopsRiskPercent(patchCriticalItems, categoryTotal), tone: patchCriticalItems ? "critical" : "good" },
            { name: "Task Failures", value: failedTaskItems, percent: itopsRiskPercent(failedTaskItems, categoryTotal), tone: failedTaskItems ? "warning" : "good" },
            { name: "Network Registration", value: networkRiskItems, percent: itopsRiskPercent(networkRiskItems, categoryTotal), tone: networkRiskItems ? "neutral" : "good" }
        ],
        osBreakdown,
        biosAgeBreakdown,
        topFindings,
        topHardwareRisk
    };
}

function buildItOpsAttentionQueue({ incidentSummary, hardware, patchSummary, software, network, geolocation, tasks }) {
    const queue = [];

    if (incidentSummary.overdueTickets > 0) {
        queue.push({
            id: "service-desk-overdue",
            module: "Service Desk",
            title: `${itopsFormatInt(incidentSummary.overdueTickets)} overdue ticket(s)`,
            subtitle: "SLA due date already passed.",
            severity: "Critical",
            tone: "danger"
        });
    }

    if (patchSummary.criticalVulnerabilities > 0) {
        queue.push({
            id: "patch-critical",
            module: "Patch",
            title: `${itopsFormatInt(patchSummary.criticalVulnerabilities)} critical missing update(s)`,
            subtitle: "Review critical vulnerability patch backlog.",
            severity: "Critical",
            tone: "danger"
        });
    }

    if (hardware.staleSync > 0) {
        queue.push({
            id: "hardware-stale",
            module: "Hardware",
            title: `${itopsFormatInt(hardware.staleSync)} stale device sync record(s)`,
            subtitle: "Device did not report within 7 days.",
            severity: "High",
            tone: "warning"
        });
    }

    if (software.unclassifiedSoftware > 0) {
        queue.push({
            id: "software-unclassified",
            module: "Software",
            title: `${itopsFormatInt(software.unclassifiedSoftware)} unclassified software row(s)`,
            subtitle: "Software category mapping should be reviewed.",
            severity: "Medium",
            tone: "warning"
        });
    }

    if (network.unregisteredIps > 0) {
        queue.push({
            id: "network-unregistered",
            module: "Network",
            title: `${itopsFormatInt(network.unregisteredIps)} unregistered IP record(s)`,
            subtitle: "Network inventory has IPs without registered device mapping.",
            severity: "Medium",
            tone: "info"
        });
    }

    if (geolocation.staleLocations > 0) {
        queue.push({
            id: "geo-stale",
            module: "Geo",
            title: `${itopsFormatInt(geolocation.staleLocations)} stale location record(s)`,
            subtitle: "MDM location is older than 7 days.",
            severity: "Medium",
            tone: "warning"
        });
    }

    if (tasks.failedTasks > 0) {
        queue.push({
            id: "task-failed",
            module: "Task List",
            title: `${itopsFormatInt(tasks.failedTasks)} stopped/cancelled task(s)`,
            subtitle: "Review job history and target endpoint status.",
            severity: "High",
            tone: "danger"
        });
    }

    return queue.slice(0, 10);
}

app.get("/api/dashboard/it-operations", authenticateToken, async (req, res) => {
    try {
        const pool = await sql.connect(dbConfig);

        const [
            hardware,
            software,
            network,
            geolocation,
            tasks,
            incidentSummary,
            patchSummary,
            departmentRows
        ] = await Promise.all([
            getItOpsHardwareSummary(pool),
            getItOpsSoftwareSummary(pool),
            getItOpsNetworkSummary(pool),
            getItOpsGeoSummary(pool),
            getItOpsTaskSummary(pool),
            getItOpsIncidentSummary(pool),
            getItOpsPatchSummary(pool),
            getItOpsDepartmentRows(pool)
        ]);

        const totalDevices = itopsToNumber(hardware.totalDevices);
        const healthyEndpoints = itopsToNumber(hardware.onlineDevices);
        const patchCompliance = itopsToNumber(patchSummary.patchCompliance);
        const slaAchievement = itopsToNumber(incidentSummary.slaAchievement);
        const openIncidents = itopsToNumber(incidentSummary.openIncidents);
        const criticalVulnerabilities = itopsToNumber(patchSummary.criticalVulnerabilities);
        const risk = await getItOpsRiskSummary(pool, { hardware, patchSummary, network, geolocation, tasks });
        const attentionQueue = buildItOpsAttentionQueue({ incidentSummary, hardware, patchSummary, software, network, geolocation, tasks });

        const data = {
            generatedAt: new Date().toISOString(),
            rangeLabel: "Last 7 Days",
            kpiCards: [
                {
                    title: "Total Devices",
                    value: itopsFormatInt(totalDevices),
                    caption: "Hardware + MDM inventory scope",
                    trend: `${itopsFormatInt(hardware.onlineDevices)} online`,
                    trendDirection: "up",
                    icon: "Laptop",
                    tone: "blue",
                    progress: itopsPercent(hardware.onlineDevices, totalDevices, 0)
                },
                {
                    title: "Open Incidents",
                    value: itopsFormatInt(openIncidents),
                    caption: "Across service desk queue",
                    trend: `${itopsFormatInt(incidentSummary.overdueTickets)} overdue`,
                    trendDirection: incidentSummary.overdueTickets > 0 ? "down" : "up",
                    icon: "Ticket",
                    tone: "amber"
                },
                {
                    title: "Running Tasks",
                    value: itopsFormatInt(tasks.runningTasks),
                    caption: "Active inventory / remote jobs",
                    trend: `${itopsFormatInt(tasks.failedTasks)} stopped or cancelled`,
                    trendDirection: tasks.failedTasks > 0 ? "down" : "up",
                    icon: "Wrench",
                    tone: "purple"
                },
                {
                    title: "Patch Compliance",
                    value: itopsFormatPercent(patchCompliance),
                    caption: "Installed vs applicable patches",
                    trend: `${itopsFormatInt(patchSummary.missingPatches)} missing patches`,
                    trendDirection: patchCompliance >= 90 ? "up" : "down",
                    icon: "Gauge",
                    tone: "cyan",
                    progress: patchCompliance
                },
                {
                    title: "Location Coverage",
                    value: itopsFormatInt(geolocation.trackedDevices),
                    caption: "Devices with location records",
                    trend: `${itopsFormatInt(geolocation.staleLocations)} stale locations`,
                    trendDirection: geolocation.staleLocations > 0 ? "down" : "up",
                    icon: "MapPin",
                    tone: "green"
                },
                {
                    title: "Critical Risks",
                    value: itopsFormatInt(risk.totalCritical),
                    caption: "Hardware, OS, BIOS, geo & patch risk",
                    trend: `${itopsFormatInt(risk.totalHigh)} high / ${itopsFormatInt(risk.score)} risk score`,
                    trendDirection: risk.totalCritical > 0 || risk.totalHigh > 0 ? "down" : "up",
                    icon: "ShieldAlert",
                    tone: "red",
                    progress: risk.score
                }
            ],
            incidentTrend: incidentSummary.incidentTrend,
            trendSummary: incidentSummary.trendSummary,
            domainHealth: [
                { name: "Endpoints", percent: itopsPercent(healthyEndpoints, totalDevices, 0), color: "#2f80ed" },
                { name: "Software", percent: itopsPercent(software.devicesWithSoftware, totalDevices, 0), color: "#22c55e" },
                { name: "Network", percent: itopsPercent(network.registeredDevices, network.knownIps, 0), color: "#8b5cf6" },
                { name: "Geolocation", percent: itopsPercent(Math.max(geolocation.trackedDevices - geolocation.staleLocations, 0), geolocation.trackedDevices, 0), color: "#f59e0b" },
                { name: "Task Queue", percent: itopsPercent(tasks.completedTasks, tasks.totalTasks, 0), color: "#06b6d4" }
            ],
            patchDepartments: patchSummary.patchDepartments.length
                ? patchSummary.patchDepartments
                : departmentRows.map(row => ({ name: row.department, percent: row.patchCompliance })).slice(0, 7),
            activeAlerts: incidentSummary.activeAlerts,
            problematicSystems: incidentSummary.problematicSystems,
            serviceDesk: {
                pendingTickets: openIncidents,
                overdueTickets: itopsToNumber(incidentSummary.overdueTickets),
                mttr: itopsFormatDuration(incidentSummary.mttrMinutes),
                firstResponse: itopsFormatDuration(incidentSummary.firstResponseMinutes),
                slaAchievement,
                priorityBreakdown: incidentSummary.priorityBreakdown
            },
            security: {
                criticalVulnerabilities,
                antiVirusStatus: "N/A",
                failedBackups: 0,
                policyExceptions: 0
            },
            hardware,
            software,
            network,
            geolocation,
            tasks,
            risk,
            attentionQueue,
            departmentRows
        };

        return res.json({ success: true, data });
    } catch (err) {
        console.error("GET /api/dashboard/it-operations error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to load IT operations dashboard",
            error: err.message
        });
    }
});




