app.post("/api/restrictions/whitelist/manage/software", authenticateToken, async (req, res) => {
    try {
        const name = normalizeRestrictionValue(req.body.Name || req.body.name || req.body.softwareName);
        if (!name) return res.status(400).json({ success: false, message: "Software name is required" });

        const pool = await sql.connect(dbConfig);
        const tableInfo = await getWhitelistTableInfo(pool);
        if (!tableInfo.hasSoftwareTable) {
            return res.status(501).json({ success: false, message: "TSSWB_WL_SW_LIST table is not available in this database." });
        }

        const result = await pool.request()
            .input("Name", sql.VarChar(255), name)
            .query(`
                IF EXISTS (SELECT 1 FROM TSSWB_WL_SW_LIST WHERE Name = @Name)
                BEGIN
                    SELECT CAST(0 AS int) AS inserted, WLSWIdn, Name FROM TSSWB_WL_SW_LIST WHERE Name = @Name;
                END
                ELSE
                BEGIN
                    IF OBJECTPROPERTY(OBJECT_ID('TSSWB_WL_SW_LIST'), 'TableHasIdentity') = 1
                    BEGIN
                        INSERT INTO TSSWB_WL_SW_LIST (Name) VALUES (@Name);
                        SELECT CAST(1 AS int) AS inserted, CAST(SCOPE_IDENTITY() AS int) AS WLSWIdn, @Name AS Name;
                    END
                    ELSE
                    BEGIN
                        DECLARE @NewId int;
                        SELECT @NewId = ISNULL(MAX(WLSWIdn), 0) + 1 FROM TSSWB_WL_SW_LIST;
                        INSERT INTO TSSWB_WL_SW_LIST (WLSWIdn, Name) VALUES (@NewId, @Name);
                        SELECT CAST(1 AS int) AS inserted, @NewId AS WLSWIdn, @Name AS Name;
                    END
                END
            `);

        const row = result.recordset?.[0];
        if (row?.inserted === 0) return res.status(409).json({ success: false, message: "Software already exists", data: row });
        return res.status(201).json({ success: true, data: row });
    } catch (err) {
        console.error("Failed to create whitelist software:", err);
        return res.status(500).json({ success: false, message: "Failed to create whitelist software", error: err.message || String(err) });
    }
});

app.put("/api/restrictions/whitelist/manage/software/:id", authenticateToken, async (req, res) => {
    try {
        const id = parseRestrictionInt(req.params.id, 0);
        const name = normalizeRestrictionValue(req.body.Name || req.body.name || req.body.softwareName);
        if (!id || !name) return res.status(400).json({ success: false, message: "Software ID and name are required" });

        const pool = await sql.connect(dbConfig);
        const tableInfo = await getWhitelistTableInfo(pool);
        if (!tableInfo.hasSoftwareTable) {
            return res.status(501).json({ success: false, message: "TSSWB_WL_SW_LIST table is not available in this database." });
        }

        await pool.request()
            .input("WLSWIdn", sql.Int, id)
            .input("Name", sql.VarChar(255), name)
            .query("UPDATE TSSWB_WL_SW_LIST SET Name = @Name WHERE WLSWIdn = @WLSWIdn;");

        return res.json({ success: true, data: { WLSWIdn: id, id, Name: name, name } });
    } catch (err) {
        console.error("Failed to update whitelist software:", err);
        return res.status(500).json({ success: false, message: "Failed to update whitelist software", error: err.message || String(err) });
    }
});

