app.post("/api/restrictions/web/groups", authenticateToken, async (req, res) => {
    try {
        const name = normalizeRestrictionValue(req.body.name || req.body.groupname);
        const description = normalizeRestrictionValue(req.body.description);
        const rawUrls = Array.isArray(req.body.urls) ? req.body.urls : Array.isArray(req.body.web_list) ? req.body.web_list : [];
        const urls = [...new Set(rawUrls.map(normalizeWebsiteRestrictionUrl).filter(Boolean))];

        if (!name) return res.status(400).json({ success: false, message: "Group name is required" });

        const pool = await sql.connect(dbConfig);
        await ensureWebsiteRestrictionTables(pool);
        const transaction = new sql.Transaction(pool);
        await transaction.begin();

        try {
            const createResult = await new sql.Request(transaction)
                .input("Name", sql.VarChar(255), name)
                .input("Description", sql.VarChar(1000), description)
                .query(`
                    IF EXISTS (SELECT 1 FROM TSWB_URL_GROUP WHERE name = @Name)
                    BEGIN
                        SELECT CAST(0 AS int) AS inserted, idx, name FROM TSWB_URL_GROUP WHERE name = @Name;
                    END
                    ELSE
                    BEGIN
                        DECLARE @NewIdx int;
                        SELECT @NewIdx = ISNULL(MAX(idx), 0) + 1 FROM TSWB_URL_GROUP WITH (UPDLOCK, HOLDLOCK);

                        IF COL_LENGTH('TSWB_URL_GROUP', 'description') IS NOT NULL
                            INSERT INTO TSWB_URL_GROUP (idx, name, description) VALUES (@NewIdx, @Name, @Description);
                        ELSE
                            INSERT INTO TSWB_URL_GROUP (idx, name) VALUES (@NewIdx, @Name);

                        SELECT CAST(1 AS int) AS inserted, @NewIdx AS idx, @Name AS name;
                    END
                `);

            const row = createResult.recordset?.[0];
            if (row?.inserted === 0) {
                await transaction.rollback();
                return res.status(409).json({ success: false, message: "Group already exists", data: row });
            }

            let seq = 0;
            for (const url of urls) {
                seq += 1;
                await new sql.Request(transaction)
                    .input("GroupId", sql.Int, row.idx)
                    .input("Seq", sql.Int, seq)
                    .input("Url", sql.VarChar(1000), url)
                    .query("INSERT INTO TSWB_URL_LIST (idx, seq, url) VALUES (@GroupId, @Seq, @Url);");
            }

            await transaction.commit();
            const detail = await getWebsiteGroupDetail(pool, row.idx);
            return res.status(201).json({ success: true, data: detail || row });
        } catch (innerErr) {
            await transaction.rollback();
            throw innerErr;
        }
    } catch (err) {
        console.error("Failed to create website group:", err);
        return res.status(500).json({ success: false, message: "Failed to create website group", error: err.message || String(err) });
    }
});

app.put("/api/restrictions/web/groups/:groupId", authenticateToken, async (req, res) => {
    try {
        const groupId = parseRestrictionInt(req.params.groupId, 0);
        const name = normalizeRestrictionValue(req.body.name || req.body.groupname);
        const description = normalizeRestrictionValue(req.body.description);
        if (!groupId || !name) return res.status(400).json({ success: false, message: "Group ID and name are required" });

        const pool = await sql.connect(dbConfig);
        await ensureWebsiteRestrictionTables(pool);
        const result = await pool.request()
            .input("GroupId", sql.Int, groupId)
            .input("Name", sql.VarChar(255), name)
            .input("Description", sql.VarChar(1000), description)
            .query(`
                IF EXISTS (SELECT 1 FROM TSWB_URL_GROUP WHERE name = @Name AND idx <> @GroupId)
                BEGIN
                    SELECT CAST(0 AS int) AS updated, 'duplicate' AS reason;
                END
                ELSE
                BEGIN
                    IF COL_LENGTH('TSWB_URL_GROUP', 'description') IS NOT NULL
                        UPDATE TSWB_URL_GROUP SET name = @Name, description = @Description WHERE idx = @GroupId;
                    ELSE
                        UPDATE TSWB_URL_GROUP SET name = @Name WHERE idx = @GroupId;
                    SELECT CAST(@@ROWCOUNT AS int) AS updated, '' AS reason;
                END
            `);

        const row = result.recordset?.[0];
        if (row?.reason === "duplicate") return res.status(409).json({ success: false, message: "Group name already exists" });
        if (Number(row?.updated || 0) === 0) return res.status(404).json({ success: false, message: "Website group was not found" });

        const detail = await getWebsiteGroupDetail(pool, groupId);
        return res.json({ success: true, data: detail || { idx: groupId, name, description } });
    } catch (err) {
        console.error("Failed to update website group:", err);
        return res.status(500).json({ success: false, message: "Failed to update website group", error: err.message || String(err) });
    }
});

